INSERT INTO public.chapters (id, subject_id, title, description, lesson_content, summary, display_order, manuel_ref) VALUES
  ('ba9daafc-27c7-5e69-aaaf-eb26f11fae73', 'svt', 'انكسار الضوء والعدسات الرقيقة', 'انكسار الضوء عند عبوره بين وسطين شفّافين؛ قوانين الانكسار؛ العدسات المجمّعة والمفرّقة والبُعد البؤري؛ الصورة عبر عدسة مجمّعة وتطبيقاتها', '# ⚔️ انكسار الضوء والعدسات الرقيقة

> 💡 «حين يعبر الضوء حدود وسطين شفّافين، يغيّر مساره كالمحارب الذكيّ الذي يُعيد ترتيب خطواته!»

## 🏰 ظاهرة الانكسار

عندما ينتقل شعاع ضوئي من وسط شفّاف إلى وسط شفّاف آخر مختلف (مثلاً من الهواء إلى الزجاج)، **يغيّر اتّجاهه** عند سطح الفصل بين الوسطين. هذه الظاهرة تُسمّى **انكسار الضوء**.

أمثلة من الحياة اليومية:

- ملعقة تبدو «مكسورة» حين توضع في كوب ماء.
- الأسماك في حوض الماء تبدو في غير مكانها الحقيقي.
- قوس قزح الناتج عن انكسار الضوء في قطرات المطر.

## ⚡ عناصر الانكسار

عند سطح الفصل بين الوسطَين عند نقطة الورود **I** نميّز:

- **الشعاع الوارد**: الشعاع الضوئي القادم من الوسط الأوّل.
- **الشعاع المنكسر**: الشعاع الذي يواصل مساره في الوسط الثاني مع تغيير الاتّجاه.
- **الناظم (N)**: الخطّ العموديّ على سطح الفصل عند نقطة الورود.
- **زاوية الورود (i₁)**: الزاوية بين الشعاع الوارد والناظم (في الوسط الأوّل).
- **زاوية الانكسار (i₂)**: الزاوية بين الشعاع المنكسر والناظم (في الوسط الثاني).

> ⚠️ تُقاس الزوايا دائمًا بين الشعاع والناظم، لا بين الشعاع وسطح الفصل.

## 🛡️ قاعدة الانكسار

إذا انتقل الضوء من وسط **أقلّ كثافة** (كالهواء) إلى وسط **أكثر كثافة** (كالماء أو الزجاج):

- **ينكسر نحو الناظم**: زاوية الانكسار **أصغر** من زاوية الورود (i₂ < i₁).

إذا انتقل من وسط **أكثر كثافة** إلى وسط **أقلّ كثافة**:

- **ينكسر بعيدًا عن الناظم**: زاوية الانكسار **أكبر** من زاوية الورود (i₂ > i₁).

> 🗡️ حالة خاصّة: إذا سقط الشعاع **عموديًّا** (i₁ = 0°) على سطح الفصل، فلا ينكسر ويواصل مساره بخطٍّ مستقيم (i₂ = 0°).

## 🔮 العدسات الرقيقة

**العدسة الرقيقة** قطعة شفّافة (عادةً زجاج) محدودة بسطحَين كرويَّين (أو سطح كروي وسطح مستوٍ). تستخدم ظاهرة الانكسار لتجميع أشعّة الضوء أو تفريقها.

نميّز نوعَين:

| النوع                    | الشكل           | التأثير                              |
| ------------------------ | --------------- | ------------------------------------ |
| **عدسة مجمّعة (محدّبة)** | أثخن في المنتصف | تجمّع الأشعّة الموازية في نقطة واحدة |
| **عدسة مفرّقة (مقعّرة)** | أرقّ في المنتصف | تفرّق الأشعّة الموازية               |

## 🌟 عناصر العدسة المجمّعة

- **المركز البصري (O)**: النقطة المركزية للعدسة؛ أيّ شعاع يمرّ بها يواصل مساره دون انكسار.
- **المحور البصري**: الخطّ العموديّ على العدسة المارّ بالمركز البصري.
- **البؤرة (F)**: النقطة التي تلتقي عندها الأشعّة الموازية للمحور بعد مرورها بالعدسة المجمّعة.
- **البُعد البؤري (f)**: المسافة بين المركز البصري والبؤرة.

$$f = OF$$

> 💡 كلّما كانت العدسة أكثر تحدّبًا (أثخن)، كان البُعد البؤري أصغر وقوّة التجميع أكبر.

## 🌑 الصورة عبر عدسة مجمّعة

تعتمد طبيعة الصورة على موضع الجسم بالنسبة للبؤرة:

| موضع الجسم                     | طبيعة الصورة | حجمها  | اتّجاهها |
| ------------------------------ | ------------ | ------ | -------- |
| خارج مسافة بؤريّتَين (d > 2f)  | حقيقية       | مصغّرة | مقلوبة   |
| عند ضعف البُعد البؤري (d = 2f) | حقيقية       | مساوية | مقلوبة   |
| بين f و 2f                     | حقيقية       | مكبّرة | مقلوبة   |
| داخل البُعد البؤري (d < f)     | تخيّلية      | مكبّرة | معتدلة   |

> 🗡️ أشعّة البناء الثلاثة: (1) الشعاع الموازي للمحور → ينكسر مارًّا بـ F. (2) الشعاع المارّ بـ O → يواصل مساره مستقيمًا. (3) الشعاع المارّ بـ F → ينكسر موازيًا للمحور.

## 🏆 التطبيقات

- **العين البشرية**: عدسة حيّة مجمّعة (العدسيّة) تكوّن صورة حقيقية مقلوبة على الشبكية. الدماغ يعيد تصحيح الاتّجاه.
- **العدسة المكبّرة**: عدسة مجمّعة تُستعمل مع وضع الجسم داخل البُعد البؤري فتعطي صورة تخيّلية مكبّرة معتدلة.
- **النظارات الطبّية**: عدسات مجمّعة (لقصار النظر المدّ) أو مفرّقة (لقصار النظر القريب) لتصحيح عيوب الإبصار.
- **الكاميرات والمجاهر**: تستعمل أنظمة من العدسات لتكبير الأجسام الدقيقة أو تصوير المشاهد البعيدة.

> 🏆 أتقنتَ أسرار الانكسار والعدسات! في الفصل القادم سننتقل إلى عالم المادّة لنكتشف الذرّات والجزيئات.', '# 📜 ملخّص: انكسار الضوء والعدسات الرقيقة

- **الانكسار**: تغيير اتّجاه الضوء عند انتقاله من وسط شفّاف إلى آخر مختلف في الكثافة البصرية.
- من وسط أقلّ كثافة إلى أكثر: ينكسر **نحو الناظم** (i₂ < i₁). والعكس بالعكس.
- شعاع عمودي على سطح الفصل (i₁ = 0°): يواصل مساره دون انكسار.
- **عدسة مجمّعة (محدّبة)**: أثخن في المنتصف، تجمّع الأشعّة الموازية في البؤرة F.
- **عدسة مفرّقة (مقعّرة)**: أرقّ في المنتصف، تفرّق الأشعّة.
- **البُعد البؤري f**: المسافة من المركز البصري O إلى البؤرة F.
- الصورة عبر عدسة مجمّعة: حقيقية مقلوبة إن كان الجسم خارج f، تخيّلية معتدلة مكبّرة إن كان داخل f.
- **تطبيقات**: العين (عدسيّة حيّة)، العدسة المكبّرة، النظارات، الكاميرات.', 3, NULL)
ON CONFLICT (id) DO UPDATE SET
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  description = EXCLUDED.description,
  lesson_content = EXCLUDED.lesson_content,
  summary = EXCLUDED.summary,
  display_order = EXCLUDED.display_order,
  manuel_ref = EXCLUDED.manuel_ref;

INSERT INTO public.chapters (id, subject_id, title, description, lesson_content, summary, display_order, manuel_ref) VALUES
  ('4c10b91f-7bff-5a39-9b21-4f29a7f25d1c', 'svt', 'الذرّات والجزيئات والرموز الكيميائية', 'مكوّنات الذرّة (نواة + إلكترونات)؛ العنصر الكيميائي ورمزه؛ الجزيء والصيغة الكيميائية؛ الفرق بين الذرّة والجزيء؛ قراءة الصيغ وعدّ الذرّات', '# ⚔️ الذرّات والجزيئات والرموز الكيميائية

> 💡 «الذرّة أصغر جنديّ في جيش المادّة — لا تراها بالعين، لكنّها تبني كلّ شيء!»

## 🏰 الذرّة: اللبنة الأساسية للمادّة

**الذرّة** هي أصغر جزء من المادّة يحتفظ بخصائص العنصر الكيميائي. حجمها صغير جدًّا جدًّا: قُطر الذرّة يقارب 10⁻¹⁰ متر (أنغستروم واحد).

تتكوّن الذرّة من جزأين رئيسيَّين:

- **النواة**: في مركز الذرّة، تحتوي على:
  - **بروتونات**: جسيمات موجبة الشحنة (+).
  - **نيوترونات**: جسيمات عديمة الشحنة (محايدة).
- **الإلكترونات**: جسيمات سالبة الشحنة (−) تدور حول النواة في مستويات طاقة تُسمّى «المدارات» أو «الأغلفة».

> ⚠️ الذرّة في مجملها **متعادلة كهربائيًّا**: عدد البروتونات = عدد الإلكترونات.

## ⚡ العنصر الكيميائي والرمز

**العنصر الكيميائي** هو مجموعة ذرّات لها نفس عدد البروتونات في النواة (يُسمّى **العدد الذري Z**).

يُمثَّل كلّ عنصر برمز دوليّ (حرف أو حرفان):

| العنصر     | الرمز | العدد الذري Z |
| ---------- | ----- | ------------- |
| الهيدروجين | H     | 1             |
| الأكسجين   | O     | 8             |
| الكربون    | C     | 6             |
| الصوديوم   | Na    | 11            |
| الكلور     | Cl    | 17            |
| النيتروجين | N     | 7             |
| الكبريت    | S     | 16            |
| الكالسيوم  | Ca    | 20            |

> 🗡️ الرمز يبدأ دائمًا بحرف كبير، ويُكمَل بحرف صغير عند الحاجة (Na لا NA ولا na).

## 🛡️ الجزيء والصيغة الكيميائية

**الجزيء** هو أصغر جزء من مادّة يحتفظ بخصائصها الكيميائية. يتكوّن من ذرّتَين أو أكثر مرتبطة بروابط كيميائية.

**الصيغة الكيميائية** تُبيّن:

- **نوع** الذرّات المكوِّنة للجزيء (الرموز).
- **عدد** كلّ نوع من الذرّات (الأرقام السفلية).

أمثلة:

| الجزيء             | الصيغة | نوع الذرّات وعددها      |
| ------------------ | ------ | ----------------------- |
| الماء              | H₂O    | ذرّتان H + ذرّة O واحدة |
| الأكسجين           | O₂     | ذرّتان O                |
| ثاني أكسيد الكربون | CO₂    | ذرّة C + ذرّتان O       |
| الميتان            | CH₄    | ذرّة C + 4 ذرّات H      |
| الأمونياك          | NH₃    | ذرّة N + 3 ذرّات H      |

> 💡 إذا لم يُكتب رقم بجانب الرمز فهو يعني ذرّة **واحدة** (H₂O: ذرّة O واحدة).

## 🔮 الفرق بين الذرّة والجزيء

|                  | الذرّة                 | الجزيء              |
| ---------------- | ---------------------- | ------------------- |
| **التعريف**      | أصغر جزء من عنصر       | مجموعة ذرّات مرتبطة |
| **التركيب**      | نواة + إلكترونات       | ذرّتان أو أكثر      |
| **مثال**         | ذرّة أكسجين O          | جزيء أكسجين O₂      |
| **الوجود الحرّ** | نادر (للغازات النبيلة) | شائع في المواد      |

> ⚠️ الأكسجين الموجود في الهواء يوجد في شكل جزيئات O₂ لا ذرّات منفردة O.

## 🌟 قراءة الصيغ وعدّ الذرّات

لعدّ ذرّات جزيء ما، اجمع الأرقام السفلية لكلّ عنصر:

**مثال:** جزيء H₂SO₄ (حمض الكبريتيك):

- ذرّتا هيدروجين (H₂) → 2
- ذرّة كبريت (S) → 1
- أربع ذرّات أكسجين (O₄) → 4
- **الإجمالي: 7 ذرّات**

**مثال:** جزيء Ca(OH)₂ (هيدروكسيد الكالسيوم):

- الرقم 2 خارج القوسَين يضرب كلّ ما بداخلهما:
- ذرّة Ca: 1 ، ذرّتا O: 2 ، ذرّتا H: 2
- **الإجمالي: 5 ذرّات**

## 🌑 العناصر في الجدول الدوري

تُصنَّف العناصر في **الجدول الدوري للعناصر** بحسب أعدادها الذريّة. يضمّ الجدول الحالي 118 عنصرًا. أهمّ ما يجب حفظه في مرحلتنا:

- **H** (هيدروجين، Z=1): أخفّ العناصر وأوفرها في الكون.
- **C** (كربون، Z=6): أساس الكيمياء العضوية والحياة.
- **N** (نيتروجين، Z=7): يشكّل 78% من هواء الغلاف الجوّي.
- **O** (أكسجين، Z=8): ضروري للتنفّس والاحتراق.
- **Na** (صوديوم، Z=11) و **Cl** (كلور، Z=17): يكوّنان معًا ملح الطعام NaCl.

## 🏆 خلاصة

```
المادّة → مكوّنة من جزيئات
الجزيء → مكوّن من ذرّات
الذرّة → نواة (بروتونات + نيوترونات) + إلكترونات
```

> 🏆 عرفتَ الآن اللبنات الأساسية للمادّة! في الفصل القادم سندرس ما يحدث حين تتفاعل الجزيئات مع بعضها: **التفاعل الكيميائي**.', '# 📜 ملخّص: الذرّات والجزيئات والرموز الكيميائية

- **الذرّة**: أصغر جزء من عنصر؛ تتكوّن من **نواة** (بروتونات + نيوترونات) + **إلكترونات** تدور حولها. الذرّة متعادلة كهربائيًّا (عدد البروتونات = عدد الإلكترونات).
- **العنصر الكيميائي**: مجموعة ذرّات بنفس العدد الذري Z. يُمثَّل برمز دوليّ: H، O، C، Na، Cl، N، S، Ca…
- **الجزيء**: أصغر جزء من مادّة يحتفظ بخصائصها؛ يتكوّن من ذرّتَين أو أكثر مرتبطة.
- **الصيغة الكيميائية**: تُبيّن نوع الذرّات وعددها: H₂O (ذرّتا H + ذرّة O)، O₂، CO₂، CH₄.
- لعدّ الذرّات: اجمع الأرقام السفلية لكلّ عنصر (الرقم غير المكتوب = 1).
- الأكسجين في الهواء يوجد على شكل جزيء **O₂** لا ذرّة منفردة.', 4, NULL)
ON CONFLICT (id) DO UPDATE SET
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  description = EXCLUDED.description,
  lesson_content = EXCLUDED.lesson_content,
  summary = EXCLUDED.summary,
  display_order = EXCLUDED.display_order,
  manuel_ref = EXCLUDED.manuel_ref;

INSERT INTO public.chapters (id, subject_id, title, description, lesson_content, summary, display_order, manuel_ref) VALUES
  ('4dffb31a-ec0d-5def-90db-3ab72e4936d7', 'svt', 'التفاعل الكيميائي والمعادلة الكيميائية', 'المتفاعلات والنواتج، انحفاظ الكتلة، كتابة المعادلة الكيميائية وموازنتها', '# ⚔️ التفاعل الكيميائي والمعادلة الكيميائية

> 💡 «في التحوّل الكيميائي تختفي موادّ وتظهر أخرى… لكن لا شيء يضيع: المادّة تتحوّل ولا تفنى.»

## 🏰 التحوّل الكيميائي

**التفاعل الكيميائي** تحوّل تختفي خلاله موادّ (المتفاعلات) وتتكوّن موادّ جديدة (النواتج) لها خصائص مختلفة.

- **المتفاعلات**: الموادّ الموجودة قبل التفاعل.
- **النواتج**: الموادّ المتكوّنة بعد التفاعل.

> 🗡️ مؤشّرات حدوث تفاعل: تغيّر اللون، انطلاق غاز، تكوّن راسب، انبعاث حرارة أو ضوء.

## ⚡ تحوّل كيميائي أم فيزيائي؟

- **تحوّل فيزيائي**: تتغيّر الحالة أو الشكل دون تغيّر طبيعة المادّة (ذوبان الجليد، تبخّر الماء).
- **تحوّل كيميائي**: تظهر موادّ **جديدة** (احتراق الورق، صدأ الحديد).

## 🛡️ قانون انحفاظ الكتلة (لافوازييه)

> «لا شيء يُفقَد، لا شيء يُخلَق، كلّ شيء يتحوّل.»

في تفاعل كيميائي، **كتلة المتفاعلات = كتلة النواتج**.

$$ m(المتفاعلات) = m(النواتج) $$

فلو تفاعل 4 g من الميثان مع 16 g من الأكسجين، كانت كتلة النواتج 20 g.

## 🔮 المعادلة الكيميائية

نكتب التفاعل بالرموز والصيغ، مع سهم من المتفاعلات نحو النواتج:

$$ المتفاعلات → النواتج $$

مثال احتراق الكربون:

$$ C + O₂ → CO₂ $$

## 🧮 موازنة المعادلة

بسبب انحفاظ المادّة، يجب أن يكون **عدد ذرّات كلّ عنصر متساويًا** في الطرفين. نضبط ذلك بإضافة **معاملات** (أعداد أمام الصيغ) دون تغيير الصيغ نفسها.

مثال احتراق الميثان:

$$ CH₄ + 2 O₂ → CO₂ + 2 H₂O $$

نتحقّق: الكربون 1 = 1، الهيدروجين 4 = 4، الأكسجين 4 = (2 + 2) = 4. ✅

> ⚠️ نوازن بتغيير **المعاملات** فقط، لا الأرقام السفلية داخل الصيغة (لا نحوّل O₂ إلى O₃).

## 🧪 منهجيّة الموازنة

1. أكتب صيغ المتفاعلات والنواتج بشكل صحيح.
2. أعدّ ذرّات كلّ عنصر في الطرفين.
3. أضبط المعاملات حتى يتساوى عدد ذرّات كلّ عنصر.
4. أتحقّق من انحفاظ كلّ العناصر.

> 🏆 صرتَ تقرأ لغة الكيمياء وتوازن معادلاتها: أساسٌ لفهم كلّ التفاعلات.', '# 📜 ملخّص: التفاعل الكيميائي والمعادلة الكيميائية

- **التفاعل الكيميائي**: تختفي **المتفاعلات** وتتكوّن **نواتج** جديدة بخصائص مختلفة.
- **تحوّل فيزيائي** (تغيّر حالة/شكل، نفس المادّة) مقابل **تحوّل كيميائي** (موادّ جديدة).
- **انحفاظ الكتلة (لافوازييه)**: كتلة المتفاعلات = كتلة النواتج.
- **المعادلة الكيميائية**: المتفاعلات ← النواتج بالرموز والصيغ.
- **الموازنة**: عدد ذرّات كلّ عنصر متساوٍ في الطرفين، نضبطه بـ **المعاملات** فقط (لا نغيّر الصيغ).
- مثال: CH₄ + 2O₂ → CO₂ + 2H₂O (كربون 1=1، هيدروجين 4=4، أكسجين 4=4).', 5, NULL)
