INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('37d2536d-d2c7-5e45-abcb-8e00d8076e79', '2c90abf4-246f-5ca7-bce2-e8a553e79052', 'بِمَ نمثّل مسار الضوء واتّجاهه؟', '[{"id":"a","text":"بنقطة"},{"id":"b","text":"بدائرة"},{"id":"c","text":"بمنحنى"},{"id":"d","text":"بشعاع ضوئي (خطّ مستقيم مسهّم)"}]'::jsonb, 'd', 'نمثّل الضوء بشعاع ضوئي، وهو خطّ مستقيم مسهّم يدلّ على المسار والاتّجاه.', 4)
