INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('a8b17c3a-a10b-5ceb-9d4f-8110c42aaee3', '2c90abf4-246f-5ca7-bce2-e8a553e79052', 'تقارب سرعة الضوء في الفراغ:', '[{"id":"a","text":"300000 km/s"},{"id":"b","text":"300 km/s"},{"id":"c","text":"3000 km/s"},{"id":"d","text":"30 km/s"}]'::jsonb, 'a', 'سرعة الضوء في الفراغ تقارب 300000 كم/ث أي 3×10⁸ م/ث.', 5)
