INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('44e1f184-a612-5cdc-a9ba-8533a8834f1d', '738049b5-6688-53ba-8f47-c5fea00f2b0b', 'حتى يتكوّن ظلّ واضح المعالم خلف جسم معتم، يُفضَّل أن يكون المنبع الضوئي:', '[{"id":"a","text":"واسعًا جدًّا"},{"id":"b","text":"غائبًا"},{"id":"c","text":"نقطيًّا (شبه نقطي)"},{"id":"d","text":"خلف الحاجز"}]'::jsonb, 'c', 'المنبع النقطي يعطي ظلًّا حادّ الحواف، أمّا المنبع الواسع فيُنتج ظلًّا وشبه ظلّ غير واضحَين.', 5)
