INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('ac9ec4ef-98fb-5e7c-a214-7301abc706a6', 'bd64fa5c-a753-51e1-9e4a-64c9b38aec2e', 'أيّ المصادر التالية يُعدّ منبعًا ضوئيًّا أوّليًّا (يُنتج الضوء بنفسه)؟', '[{"id":"a","text":"القمر"},{"id":"b","text":"مرآة مستوية"},{"id":"c","text":"الشمس"},{"id":"d","text":"صفحة كتاب بيضاء"}]'::jsonb, 'c', 'المنبع الأوّلي يُنتج الضوء بنفسه (الشمس، اللمبة، الشمعة). أمّا القمر والمرآة والصفحة فهي أجسام مُضاءة تعكس الضوء فقط، لذا تُسمّى منابع ثانوية.', 1)
