INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('24f62805-f78c-5520-b5bb-5d7cc5912bce', 'bd64fa5c-a753-51e1-9e4a-64c9b38aec2e', 'حتى نرى جسمًا غير مُضيء بذاته، يجب أن:', '[{"id":"a","text":"يكون الجسم ساخنًا"},{"id":"b","text":"يصل إلى العين ضوءٌ قادمٌ من ذلك الجسم"},{"id":"c","text":"يكون الجسم شفّافًا"},{"id":"d","text":"تُغلق العين قليلًا"}]'::jsonb, 'b', 'نرى جسمًا غير مُضيء عندما يضيئه منبعٌ ما فيعكس جزءًا من الضوء نحو أعيننا. الرؤية تتطلّب وصول الضوء من الجسم إلى العين، لذلك لا نرى شيئًا في الظلام التامّ.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
