INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('ecad3e23-8b4b-5d24-b6f8-db4be5a0cb02', 'bd64fa5c-a753-51e1-9e4a-64c9b38aec2e', 'ينتشر الضوء في الوسط الشفّاف المتجانس:', '[{"id":"a","text":"وفق خطوط منحنية"},{"id":"b","text":"وفق خطوط مستقيمة"},{"id":"c","text":"على شكل دوائر"},{"id":"d","text":"بسرعة متناقصة باستمرار"}]'::jsonb, 'b', 'مبدأ الانتشار المستقيمي للضوء: في وسط شفّاف ومتجانس (كالهواء النقي أو الزجاج) ينتشر الضوء على شكل خطوط مستقيمة، وهذا ما يفسّر تكوّن الظلّ والكسوف والخسوف.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('185051a9-b4d0-5d1d-992d-788e9733a5bc', 'bd64fa5c-a753-51e1-9e4a-64c9b38aec2e', 'نرسم حُزمة ضوئية تخرج من منبع نقطي وتتّسع كلّما ابتعدنا عنه. هذه الحُزمة:', '[{"id":"a","text":"متوازية"},{"id":"b","text":"متقاربة"},{"id":"c","text":"متباعدة"},{"id":"d","text":"أسطوانية"}]'::jsonb, 'c', 'الحزمة المتباعدة تنطلق من نقطة واحدة (المنبع النقطي) وتتّسع مع الابتعاد. أمّا المتقاربة فتضيق نحو نقطة، والمتوازية تحافظ على عرضها ثابتًا.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('942eb056-53f3-52d8-8628-e902335d9be2', 'bd64fa5c-a753-51e1-9e4a-64c9b38aec2e', 'عمود طوله 2 m يُلقي ظلًّا طوله 3 m تحت الشمس. شجرة بجواره ظلّها 12 m. ما ارتفاع الشجرة؟', '[{"id":"a","text":"8 m"},{"id":"b","text":"18 m"},{"id":"c","text":"6 m"},{"id":"d","text":"24 m"}]'::jsonb, 'a', 'لأنّ الأشعّة الشمسية متوازية، تتناسب الأطوال مع أطوال الظلال (مثلّثات متشابهة): الارتفاع/الظلّ ثابت = 2/3. ارتفاع الشجرة = (2/3) × 12 = 8 m.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('200390e1-5733-51b7-98d2-ec4b112f8f0d', 'bd64fa5c-a753-51e1-9e4a-64c9b38aec2e', 'في غرفة مظلمة ذات ثقب، عند تقريب الشاشة من الثقب فإنّ الصورة المتكوّنة:', '[{"id":"a","text":"تكبر وتبقى مقلوبة"},{"id":"b","text":"تصغر وتبقى مقلوبة"},{"id":"c","text":"تصبح معتدلة"},{"id":"d","text":"تختفي تمامًا"}]'::jsonb, 'b', 'نتيجة الانتشار المستقيمي عبر الثقب تكون الصورة مقلوبة دائمًا. كلّما اقتربت الشاشة من الثقب صغرت الصورة، وكلّما ابتعدت كبرت، لكنّها تبقى مقلوبة في الحالتين.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('62fe9a02-8d50-5717-a76e-be41608003fe', 'bbf34e0d-c9ae-578e-8880-c3b5d4ecf5d4', 'svt', '👑 تحدّي المناظرة ⭐⭐⭐⭐: الانتشار المستقيمي — ظلال وكسوف وتناسب', 4, 300, 60, 'challenge', 'admin', 6)
ON CONFLICT (id) DO UPDATE SET
  chapter_id = EXCLUDED.chapter_id,
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  difficulty = EXCLUDED.difficulty,
  xp_reward = EXCLUDED.xp_reward,
  reward_coins = EXCLUDED.reward_coins,
  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('3e7541f5-f14c-542e-8c46-f9b9f081b9a1', '62fe9a02-8d50-5717-a76e-be41608003fe', 'مصدر ضوئيّ نقطيّ S، ووُضِع أمامه قرصٌ معتِم نصف قطره 4 cm على بُعد 30 cm من S. تُستقبَل صورة الظلّ على حاجز يبعد 90 cm عن S. ما نصف قطر الظلّ على الحاجز؟', '[{"id":"a","text":"12 cm"},{"id":"b","text":"4 cm"},{"id":"c","text":"8 cm"},{"id":"d","text":"1,3 cm"}]'::jsonb, 'a', 'بتالِس (تناسب الأشعّة الخارجة من S): نصف قطر الظلّ R على البُعد الكلّيّ من المصدر يتناسب مع نصف قطر القرص على بُعده. R/4 = 90/30 = 3، إذن R = 4 × 3 = 12 cm. ✓ الخطأ الشائع: قياس المسافة من القرص إلى الحاجز (90 − 30 = 60) بدل قياسها من المصدر، فيخرج 4 × 60/30 = 8 cm؛ أو نسيان التكبير كلّيًّا (4 cm)؛ أو قلب النسبة (4 × 30/90 = 1,3 cm).', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('d35dce95-f600-5003-afeb-11f1b341038b', '62fe9a02-8d50-5717-a76e-be41608003fe', 'قال تلميذ: «الصورة المتكوّنة على زجاج الغرفة المظلمة (الصندوق ذي الثقب) تكون معتدلة، في نفس اتجاه الشجرة». ما الخطأ؟', '[{"id":"a","text":"الصورة مقلوبة لأنّ الأشعّة المستقيمة تتقاطع عند الثقب"},{"id":"b","text":"الصورة معتدلة فعلًا، لا خطأ"},{"id":"c","text":"الصورة مقلوبة لأنّ الضوء ينحني في الثقب"},{"id":"d","text":"لا تتكوّن صورة أصلًا"}]'::jsonb, 'a', 'بسبب الانتشار المستقيميّ، الشعاع القادم من أعلى الشجرة يمرّ عبر الثقب ويصل إلى أسفل الزجاج، والقادم من الأسفل يصل إلى الأعلى، فتتقاطع الأشعّة عند الثقب وتنقلب الصورة (مقلوبة). (تمرين «صيد الخطأ».) الخطأ الشائع: ظنّ الصورة معتدلة؛ والضوء لا ينحني بل ينتشر في خطوط مستقيمة.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('e0cb142e-9bd3-54b9-b278-8497a5778a1f', '62fe9a02-8d50-5717-a76e-be41608003fe', 'في لحظةٍ من النهار، يُعطي شخصٌ طوله 1,8 m ظلًّا طوله 1,2 m تحت أشعّة الشمس. في اللحظة نفسها، كم يبلغ ارتفاع عمارةٍ ظلُّها 24 m؟', '[{"id":"a","text":"36 m"},{"id":"b","text":"16 m"},{"id":"c","text":"43,2 m"},{"id":"d","text":"20 m"}]'::jsonb, 'a', 'أشعّة الشمس متوازية، فنسبة (الارتفاع / طول الظلّ) واحدةٌ لكلّ الأجسام في اللحظة نفسها: الارتفاع/24 = 1,8/1,2 = 1,5، إذن الارتفاع = 24 × 1,5 = 36 m. ✓ الخطأ الشائع: قلب النسبة (24 × 1,2/1,8 = 16 m)؛ أو نسيان القسمة على طول ظلّ الشخص (24 × 1,8 = 43,2 m).', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('4f981652-61a3-523b-b0af-da6ed1235df5', '62fe9a02-8d50-5717-a76e-be41608003fe', 'يحدث كسوفٌ كلّيٌّ للشمس لأنّ القطر الظاهريّ للقمر يساوي تقريبًا القطر الظاهريّ للشمس. القمر قطره 3,5 × 10³ km ويبعد 3,84 × 10⁵ km. إذا كان قطر الشمس 1,4 × 10⁶ km، فعلى أيّ بُعدٍ تقريبًا يتساوى القطران الظاهريّان؟', '[{"id":"a","text":"1,5 × 10⁸ km"},{"id":"b","text":"3,84 × 10⁵ km"},{"id":"c","text":"1,3 × 10⁴ km"},{"id":"d","text":"5,4 × 10¹¹ km"}]'::jsonb, 'a', 'القطر الظاهريّ يتناسب مع (القطر الحقيقيّ / البُعد). نساوي: 1,4 × 10⁶ / D = 3,5 × 10³ / 3,84 × 10⁵. إذن D = 1,4 × 10⁶ × 3,84 × 10⁵ / (3,5 × 10³) = 1,536 × 10⁸ ≈ 1,5 × 10⁸ km (وهو فعلًا بُعد الأرض عن الشمس). ✓ الخطأ الشائع: الضرب دون القسمة (1,4 × 10⁶ × 3,84 × 10⁵ = 5,4 × 10¹¹)؛ أو نسخ بُعد القمر (3,84 × 10⁵)؛ أو قلب النسبة (1,3 × 10⁴).', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('cd876f84-8fb4-566f-a4e4-5d2ff483463f', '62fe9a02-8d50-5717-a76e-be41608003fe', 'أثناء خسوف القمر (احتجاب ضوء القمر)، كيف تصطفّ الأجرام الثلاثة؟', '[{"id":"a","text":"الأرض تقع بين الشمس والقمر (يدخل القمر مخروط ظلّ الأرض)"},{"id":"b","text":"القمر يقع بين الشمس والأرض"},{"id":"c","text":"الشمس تقع بين الأرض والقمر"},{"id":"d","text":"الأجرام الثلاثة غير مصطفّة"}]'::jsonb, 'a', 'في خسوف القمر تكون الأرض بين الشمس والقمر، فيدخل القمر في مخروط ظلّ الأرض ويحتجب ضوؤه. ✓ الخطأ الشائع: الخلط مع الكسوف — في كسوف الشمس يكون القمرُ بين الشمس والأرض فيحجب ضوء الشمس عن جزءٍ من الأرض؛ عكس ترتيب الخسوف.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('8f0a5aaa-bfb2-5c47-bac4-49245cdeb792', '62fe9a02-8d50-5717-a76e-be41608003fe', 'تُعطي غرفةٌ مظلمة (صندوق ذو ثقب) صورةً لشجرةٍ على زجاجها المُبطَّن ارتفاعها 4 cm عندما يكون عمق الصندوق 12 cm. إذا زِيد العمق إلى 18 cm (نفس الشجرة ونفس بُعدها)، ما ارتفاع الصورة الجديد؟', '[{"id":"a","text":"6 cm"},{"id":"b","text":"4 cm"},{"id":"c","text":"2,7 cm"},{"id":"d","text":"8 cm"}]'::jsonb, 'a', 'ارتفاع الصورة يتناسب طردًا مع عمق الصندوق (البُعد والشجرة ثابتان): الصورة الجديدة = 4 × 18/12 = 6 cm. ✓ الخطأ الشائع: اعتبار الصورة لا تتغيّر (4 cm)؛ أو قلب النسبة (4 × 12/18 = 2,7 cm).', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

