INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('44ddcd17-bb19-5228-ba8b-4211de3562b1', '71b0fee4-b5db-52e4-8e51-14426ab378c6', 'ما الذي يحدث للضوء عند اصطدامه بسطح المرآة المستوية؟', '[{"id":"a","text":"ينفذ عبرها"},{"id":"b","text":"يرتدّ (ينعكس)"},{"id":"c","text":"يُمتصّ كلّيًّا"},{"id":"d","text":"يتوقّف"}]'::jsonb, 'b', 'سطح المرآة العاكس لا يسمح للضوء بالنفاذ خلفه ولا يمتصّه، فالضوء الساقط يرتدّ عنه عائدًا إلى الوسط نفسه؛ هذه الظاهرة هي الانعكاس. ولأنّ السطح أملس ومنتظم يكون الانعكاس منتظمًا فتتكوّن صورة واضحة.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('5e56c005-d7b1-56c6-939c-b2c6cfdb7d38', '71b0fee4-b5db-52e4-8e51-14426ab378c6', 'ما هو الناظم عند نقطة الورود؟', '[{"id":"a","text":"الشعاع الوارد نفسه"},{"id":"b","text":"الخطّ الموازي لسطح المرآة"},{"id":"c","text":"الشعاع المنعكس"},{"id":"d","text":"الخطّ العموديّ على سطح المرآة عند نقطة الورود"}]'::jsonb, 'd', 'الناظم هو الخطّ العموديّ على سطح المرآة عند نقطة الورود، ومنه تُقاس زاويتا الورود والانعكاس.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('afa792ec-5971-53a8-a4ca-10f21e3027d3', '71b0fee4-b5db-52e4-8e51-14426ab378c6', 'سقط شعاع ضوئي على مرآة مستوية بزاوية ورود تساوي 40°. ما زاوية الانعكاس؟', '[{"id":"a","text":"80°"},{"id":"b","text":"50°"},{"id":"c","text":"90°"},{"id":"d","text":"40°"}]'::jsonb, 'd', 'وفق القانون الثاني للانعكاس: زاوية الانعكاس = زاوية الورود، إذن r = i = 40°.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('8784db1c-4b9f-524a-a0e7-124a23220be1', '71b0fee4-b5db-52e4-8e51-14426ab378c6', 'إذا سقط شعاع ضوئي عموديًّا على مرآة مستوية (i = 0°)، فإنّه:', '[{"id":"a","text":"ينكسر ويتحوّل مساره"},{"id":"b","text":"يُمتصّ كلّيًّا"},{"id":"c","text":"ينتشر في كلّ الاتّجاهات"},{"id":"d","text":"يرتدّ على نفس مساره"}]'::jsonb, 'd', 'عندما i = 0° فإنّ r = 0° أيضًا، فيرتدّ الشعاع على نفس مساره (بعكس اتّجاهه).', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('da07a20a-588b-5a3f-8fd5-7530377d7fd5', '71b0fee4-b5db-52e4-8e51-14426ab378c6', 'ما هي خصائص صورة جسم في مرآة مستوية؟', '[{"id":"a","text":"حقيقية ومكبّرة"},{"id":"b","text":"حقيقية ومقلوبة"},{"id":"c","text":"تخيّلية ومماثلة ومتناظرة"},{"id":"d","text":"تخيّلية ومصغّرة"}]'::jsonb, 'c', 'صورة الجسم في المرآة المستوية تخيّلية (لا تُسقط على شاشة)، مماثلة (نفس الحجم)، ومتناظرة مع الجسم بالنسبة للمرآة.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('7b11338c-156d-51a0-8261-6e81584fe742', '71b0fee4-b5db-52e4-8e51-14426ab378c6', 'جسم يقع على بُعد 8 سم من مرآة مستوية. على أيّ بُعد من المرآة تقع صورته؟', '[{"id":"a","text":"4 سم"},{"id":"b","text":"16 سم"},{"id":"c","text":"2 سم"},{"id":"d","text":"8 سم"}]'::jsonb, 'd', 'الجسم وصورته متناظران بالنسبة للمرآة، فالمسافة من الجسم إلى المرآة = المسافة من الصورة إلى المرآة = 8 سم.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('a18d4cb2-cdcc-506c-86e8-d099fa6d96e1', 'b0333447-8e00-556a-97b4-680f9c12f200', 'svt', '⚔️ زعيم الفصل: سيّد الانعكاس', 3, 120, 30, 'boss', 'admin', 2)
