INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('c5e3e513-f9d8-5784-92af-6817ddd63335', 'a18d4cb2-cdcc-506c-86e8-d099fa6d96e1', 'يقول القانون الأوّل للانعكاس إنّ الشعاع الوارد والشعاع المنعكس والناظم:', '[{"id":"a","text":"يقعان في مستويَين متعامدَين"},{"id":"b","text":"الشعاع الوارد والمنعكس متوازيان دائمًا"},{"id":"c","text":"الناظم عموديّ على الشعاع المنعكس فقط"},{"id":"d","text":"يقعون في مستوٍ واحد"}]'::jsonb, 'd', 'القانون الأوّل للانعكاس: الشعاع الوارد والشعاع المنعكس والناظم عند نقطة الورود كلّها تقع في مستوٍ واحد.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('df25cbc2-c7e3-5ff2-9847-7b1d36b7ee43', 'a18d4cb2-cdcc-506c-86e8-d099fa6d96e1', 'سقط شعاع ضوئي على مرآة مستوية فكانت زاوية انعكاسه 55°. ما زاوية وروده؟', '[{"id":"a","text":"110°"},{"id":"b","text":"35°"},{"id":"c","text":"90°"},{"id":"d","text":"55°"}]'::jsonb, 'd', 'بتطبيق قانون الانعكاس i = r، إذا كانت زاوية الانعكاس 55° فزاوية الورود = 55° أيضًا.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('83068f98-093a-50c4-a79b-d309fd03c87a', 'a18d4cb2-cdcc-506c-86e8-d099fa6d96e1', 'أيّ من الجمل التالية صحيحة حول الصورة في المرآة المستوية؟', '[{"id":"a","text":"الصورة حقيقية يمكن إسقاطها على شاشة"},{"id":"b","text":"الصورة مكبّرة دائمًا بالنسبة للجسم"},{"id":"c","text":"بُعد الصورة عن المرآة يساوي بُعد الجسم عن المرآة"},{"id":"d","text":"الصورة مقلوبة رأسًا على عقب"}]'::jsonb, 'c', 'الجسم وصورته متناظران بالنسبة لمستوى المرآة، فبُعدهما عن المرآة متساوٍ. الصورة تخيّلية ومماثلة وليست مقلوبة.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('3f12af12-f050-52c2-a1db-8fad4a8decaa', 'a18d4cb2-cdcc-506c-86e8-d099fa6d96e1', 'جسم طوله 10 سم يقف أمام مرآة مستوية. ما طول صورته؟', '[{"id":"a","text":"10 سم"},{"id":"b","text":"5 سم"},{"id":"c","text":"20 سم"},{"id":"d","text":"يعتمد على بُعده من المرآة"}]'::jsonb, 'a', 'الصورة في المرآة المستوية مماثلة، أي نفس حجم الجسم تمامًا. طول الصورة = طول الجسم = 10 سم بغضّ النظر عن البُعد.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('c9ea1556-ee82-55db-8a40-d7be20088539', 'a18d4cb2-cdcc-506c-86e8-d099fa6d96e1', 'شعاع ضوئي يسقط على مرآة مستوية بزاوية 30° مع سطح المرآة (لا مع الناظم). ما زاوية الانعكاس؟', '[{"id":"a","text":"30°"},{"id":"b","text":"90°"},{"id":"c","text":"60°"},{"id":"d","text":"45°"}]'::jsonb, 'c', 'زاوية الورود تُقاس مع الناظم لا مع السطح. إذا كانت الزاوية مع السطح 30°، فزاوية الورود = 90° - 30° = 60°، وبالتالي زاوية الانعكاس = 60°.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('b9988cb9-26e9-527f-bbc6-edcb45251559', 'a18d4cb2-cdcc-506c-86e8-d099fa6d96e1', 'لماذا نستطيع رؤية وجوهنا في مرآة مستوية؟', '[{"id":"a","text":"لأنّ المرآة تنتج الضوء من تلقاء نفسها"},{"id":"b","text":"لأنّ المرآة شفّافة تمامًا"},{"id":"c","text":"لأنّ الضوء ينكسر بزاوية كبيرة داخل الزجاج"},{"id":"d","text":"لأنّ الضوء الساقط على وجهنا ينعكس عنه ثمّ ينعكس عن المرآة نحو أعيننا"}]'::jsonb, 'd', 'الضوء (من مصدر خارجي) يسقط على وجهنا وينعكس عنه، ثمّ يسقط على المرآة وينعكس نحو أعيننا فنرى صورتنا.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('802a58c4-205d-5404-88cb-873dc6024953', 'b0333447-8e00-556a-97b4-680f9c12f200', 'svt', '👑 تحدّي النخبة: سيّد قوانين الانعكاس', 4, 300, 60, 'challenge', 'admin', 4)
ON CONFLICT (id) DO UPDATE SET
  chapter_id = EXCLUDED.chapter_id,
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  difficulty = EXCLUDED.difficulty,
  xp_reward = EXCLUDED.xp_reward,
  reward_coins = EXCLUDED.reward_coins,
  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('c4bf55ac-d8ad-558b-98bb-ecb3ad61c8b3', '802a58c4-205d-5404-88cb-873dc6024953', 'شعاع ضوئي يسقط على مرآة مستوية بزاوية ورود i = 35°. ما مقدار الانحراف الكلّي للشعاع، أي الزاوية المحصورة بين امتداد الشعاع الوارد والشعاع المنعكس؟', '[{"id":"a","text":"70°"},{"id":"b","text":"35°"},{"id":"c","text":"110°"},{"id":"d","text":"145°"}]'::jsonb, 'c', 'الانحراف الكلّي D هو الزاوية بين امتداد الشعاع الوارد والشعاع المنعكس. في مثلّث الانعكاس: D = 180° − 2i. هنا: D = 180° − 2×35° = 180° − 70° = 110°. الخطأ الشائع هو أخذ 2i = 70° مباشرةً (الاختيار أ) أو مجرّد قيمة i (الاختيار ب).', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('3bc9220a-2125-54eb-a2af-8c35cd392979', '802a58c4-205d-5404-88cb-873dc6024953', 'الزاوية بين شعاع ضوئي وارد وشعاعه المنعكس على مرآة مستوية تساوي 100°. ما زاوية ورود هذا الشعاع على الناظم؟', '[{"id":"a","text":"100°"},{"id":"b","text":"80°"},{"id":"c","text":"25°"},{"id":"d","text":"50°"}]'::jsonb, 'd', 'الزاوية بين الشعاع الوارد والشعاع المنعكس = i + r = 2i (لأنّ i = r). إذن: 2i = 100°، فزاوية الورود i = 50°. الاختيار ب يخلط بين الزاوية مع السطح (90°−i = 40°) ومضاعفها، والاختيار ج يقسم الزاوية على 4 خطأً.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('9ffaa4d7-476c-5ba9-a6cd-5c815d1ecc30', '802a58c4-205d-5404-88cb-873dc6024953', 'مرآة مستوية تدور بزاوية 20° حول نقطة ورود الشعاع عليها، في حين يبقى الشعاع الوارد ثابتًا. بكم تتغيّر زاوية الشعاع المنعكس؟', '[{"id":"a","text":"20°"},{"id":"b","text":"40°"},{"id":"c","text":"10°"},{"id":"d","text":"60°"}]'::jsonb, 'b', 'عند دوران المرآة بزاوية α مع ثبات الشعاع الوارد، يدور الناظم بنفس الزاوية α. وبما أنّ زاوية الورود الجديدة تزيد بمقدار α، وزاوية الانعكاس الجديدة تزيد بمقدار α كذلك، فإنّ الشعاع المنعكس يدور بمقدار 2α. هنا: 2×20° = 40°. هذه القاعدة أساسيّة في أجهزة الرصد البصري.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('9bd27914-983c-56aa-985d-942d6ab0042e', '802a58c4-205d-5404-88cb-873dc6024953', 'مرآتان مستويتان M1 و M2 تتقاطعان بزاوية 60°. يسقط شعاع ضوئي على M1 بزاوية ورود i₁ = 30° (بالنسبة للناظم). ما زاوية الورود i₂ على المرآة M2 بعد الانعكاس عن M1؟', '[{"id":"a","text":"60°"},{"id":"b","text":"45°"},{"id":"c","text":"30°"},{"id":"d","text":"90°"}]'::jsonb, 'c', 'بعد الانعكاس عن M1: r₁ = i₁ = 30°، فيصنع الشعاع المنعكس زاوية (90°−30°) = 60° مع سطح M1. في المثلّث المتكوّن بين الشعاع المنعكس والمرآتين: مجموع الزوايا = 180°، ومنها: زاوية الرأس (بين M1 و M2) = 60°، والزاوية عند M1 = 90°−r₁ = 60°. إذن الزاوية عند M2 = 180°−60°−60° = 60°، فزاوية الورود على M2: i₂ = 90°−60° = 30°.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('57895b66-95e6-591c-8fbb-83ac61367c85', '802a58c4-205d-5404-88cb-873dc6024953', 'مرآتان مستويتان M1 (أفقية) و M2 (رأسية) متعامدتان. يسقط شعاع ضوئي على M1 بزاوية ورود i₁ = 55° (بالنسبة للناظم الرأسي لـ M1). ما زاوية ورود الشعاع على M2 بعد انعكاسه عن M1؟', '[{"id":"a","text":"55°"},{"id":"b","text":"90°"},{"id":"c","text":"35°"},{"id":"d","text":"45°"}]'::jsonb, 'c', 'بعد الانعكاس عن M1 (الأفقية): r₁ = i₁ = 55° من الناظم الرأسي، أي أنّ الشعاع المنعكس يُشكّل 55° مع الرأسي و(90°−55°)=35° مع الأفقي. عند وصوله إلى M2 (الرأسية)، يكون ناظم M2 أفقيًّا، فزاوية الورود = الزاوية بين الشعاع والأفقي = 35°. القاعدة العامّة للمرآتين المتعامدتَين: i₁ + i₂ = 90°.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('3eb88fb5-b9a8-53a8-8c86-811a9c549cf3', '802a58c4-205d-5404-88cb-873dc6024953', 'جسم نقطيّ A يقف أمام مرآة مستوية M1 على بُعد 7 سم منها. ما المسافة بين الجسم A وصورته A′ في المرآة M1؟', '[{"id":"a","text":"7 سم"},{"id":"b","text":"3.5 سم"},{"id":"c","text":"14 سم"},{"id":"d","text":"21 سم"}]'::jsonb, 'c', 'خاصيّة المرآة المستوية: الجسم وصورته متناظران بالنسبة لمستوى المرآة. أي أنّ بُعد الصورة عن المرآة = بُعد الجسم عن المرآة = 7 سم. الجسم A أمام المرآة بـ7 سم، وصورته A′ خلف المرآة بـ7 سم. إذن المسافة الكلّية بين A وA′ = 7 + 7 = 14 سم. الخطأ الشائع: الاعتقاد بأنّ المسافة = 7 سم (بُعد الجسم وحده)، أو 3.5 سم (نصف البُعد).', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('1017affc-675d-5736-8633-6a06b0ebb7ce', 'b0333447-8e00-556a-97b4-680f9c12f200', 'svt', '🎯 تدرّب على انعكاس الضوء والمرآة المستوية', 3, 120, 30, 'boss', 'admin', 5)
ON CONFLICT (id) DO UPDATE SET
  chapter_id = EXCLUDED.chapter_id,
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  difficulty = EXCLUDED.difficulty,
  xp_reward = EXCLUDED.xp_reward,
  reward_coins = EXCLUDED.reward_coins,
  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('9539d202-3573-5812-a69f-9338b100fc37', '1017affc-675d-5736-8633-6a06b0ebb7ce', 'في ظاهرة الانعكاس، تُقاس زاوية الورود وزاوية الانعكاس بالنسبة إلى:', '[{"id":"a","text":"سطح المرآة"},{"id":"b","text":"الناظم (العمودي على المرآة في نقطة الورود)"},{"id":"c","text":"الشعاع المنعكس"},{"id":"d","text":"الأرض"}]'::jsonb, 'b', 'تُقاس الزاويتان دائمًا بين الشعاع (الوارد أو المنعكس) والناظم، وهو الخطّ العمودي على سطح المرآة في نقطة الورود، وليس بالنسبة إلى سطح المرآة نفسه.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('666b8805-1ec2-526f-80f6-6a7b58aa4246', '1017affc-675d-5736-8633-6a06b0ebb7ce', 'ينصّ القانون الثاني للانعكاس على أنّ:', '[{"id":"a","text":"زاوية الانعكاس أكبر من زاوية الورود"},{"id":"b","text":"زاوية الانعكاس تساوي زاوية الورود"},{"id":"c","text":"زاوية الانعكاس أصغر من زاوية الورود"},{"id":"d","text":"مجموع الزاويتين 90°"}]'::jsonb, 'b', 'القانون الثاني للانعكاس: زاوية الانعكاس = زاوية الورود. أمّا القانون الأوّل فينصّ على أنّ الشعاع الوارد والمنعكس والناظم تقع في مستوٍ واحد.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('7450115a-942a-5498-95ed-2130056127e3', '1017affc-675d-5736-8633-6a06b0ebb7ce', 'شعاع ضوئي يرد على مرآة مستوية بزاوية ورود 30°. ما زاوية الانعكاس؟', '[{"id":"a","text":"60°"},{"id":"b","text":"90°"},{"id":"c","text":"30°"},{"id":"d","text":"15°"}]'::jsonb, 'c', 'حسب القانون الثاني، زاوية الانعكاس = زاوية الورود = 30°. الخطأ الشائع 60° ناتج عن قياس الزاوية بالنسبة إلى سطح المرآة (90 − 30) بدل الناظم.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('0c5a87bd-2071-5540-9306-06bc9c7d0020', '1017affc-675d-5736-8633-6a06b0ebb7ce', 'شعاع يرد عموديًّا تمامًا على مرآة مستوية (على امتداد الناظم). كيف ينعكس؟', '[{"id":"a","text":"ينعكس بزاوية 45°"},{"id":"b","text":"يرتدّ على نفس مساره عائدًا (زاوية الانعكاس 0°)"},{"id":"c","text":"ينزلق على سطح المرآة"},{"id":"d","text":"ينفذ خلال المرآة"}]'::jsonb, 'b', 'إذا ورد الشعاع على امتداد الناظم فزاوية الورود = 0°، فتكون زاوية الانعكاس = 0° أيضًا، أي يرتدّ الشعاع على نفسه عائدًا في الاتّجاه المعاكس.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('d2939e1a-198b-5006-b42d-216f92ec2e2b', '1017affc-675d-5736-8633-6a06b0ebb7ce', 'صورة جسم في مرآة مستوية هي:', '[{"id":"a","text":"حقيقية ومقلوبة"},{"id":"b","text":"تخيّلية ومماثلة للجسم ومتناظرة معه بالنسبة إلى المرآة"},{"id":"c","text":"حقيقية ومكبّرة"},{"id":"d","text":"تخيّلية ومصغّرة"}]'::jsonb, 'b', 'صورة الجسم في المرآة المستوية تخيّلية (لا تُستقبل على شاشة)، بنفس حجم الجسم (مماثلة)، وتقع على بُعدٍ خلف المرآة يساوي بُعد الجسم أمامها (متناظرة بالنسبة إلى سطح المرآة).', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('47a56900-6f8e-5ea8-8743-6189654ece6c', '1017affc-675d-5736-8633-6a06b0ebb7ce', 'يقف شخص على بُعد 1.5 m أمام مرآة مستوية. ما المسافة بينه وبين صورته؟', '[{"id":"a","text":"1.5 m"},{"id":"b","text":"0.75 m"},{"id":"c","text":"3 m"},{"id":"d","text":"4.5 m"}]'::jsonb, 'c', 'تقع الصورة خلف المرآة على نفس بُعد الجسم أمامها = 1.5 m. فالمسافة بين الشخص وصورته = 1.5 + 1.5 = 3 m. الخطأ الشائع 1.5 m يأتي من نسيان أنّ الصورة خلف المرآة.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('ce2d82de-fd4b-5292-9f1e-84aa27931530', 'b0333447-8e00-556a-97b4-680f9c12f200', 'svt', '👑 تحدّي المناظرة ⭐⭐⭐⭐: انعكاس الضوء — الناظم والمرايا والصور', 4, 300, 60, 'challenge', 'admin', 6)
ON CONFLICT (id) DO UPDATE SET
  chapter_id = EXCLUDED.chapter_id,
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  difficulty = EXCLUDED.difficulty,
  xp_reward = EXCLUDED.xp_reward,
  reward_coins = EXCLUDED.reward_coins,
  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('07ab7a71-73c4-5d3c-8616-70204abf2320', 'ce2d82de-fd4b-5292-9f1e-84aa27931530', 'يسقط شعاع ضوئيّ على مرآة مستوية فيصنع زاوية 25° مع سطح المرآة. ما زاوية الانعكاس (المقيسة بالنسبة إلى الناظم)؟', '[{"id":"a","text":"65°"},{"id":"b","text":"25°"},{"id":"c","text":"130°"},{"id":"d","text":"50°"}]'::jsonb, 'a', 'الزوايا في الانعكاس تُقاس دائمًا بالنسبة إلى الناظم (العموديّ على المرآة)، لا إلى سطح المرآة. زاوية الورود = 90° − 25° = 65°، وبقانون الانعكاس زاوية الانعكاس = زاوية الورود = 65°. ✓ الخطأ الشائع: أخذ 25° مباشرةً (قياس من المرآة لا من الناظم)؛ أو إعطاء الزاوية بين الشعاعين الوارد والمنعكس (2 × 65 = 130°)؛ أو 2 × 25 = 50°.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('0780c650-e18f-5b4d-9b56-f073af51e6c2', 'ce2d82de-fd4b-5292-9f1e-84aa27931530', 'قال تلميذ: «زاوية ورود الشعاع على المرآة تُقاس بين الشعاع الوارد وسطح المرآة». ما الخطأ؟', '[{"id":"a","text":"تُقاس بين الشعاع الوارد والناظم (العموديّ على المرآة)"},{"id":"b","text":"تُقاس بين الشعاع الوارد والمنعكس"},{"id":"c","text":"لا خطأ، تُقاس مع سطح المرآة"},{"id":"d","text":"تُقاس بين الناظم والمرآة"}]'::jsonb, 'a', 'زاوية الورود (وكذلك الانعكاس) تُقاس دائمًا بالنسبة إلى الناظم — المستقيم العموديّ على المرآة عند نقطة الورود — لا بالنسبة إلى سطح المرآة. (تمرين «صيد الخطأ».) الخطأ الشائع: قياس الزاوية من سطح المرآة، فتخرج كلّ الحسابات بزاوية مكمّلة خاطئة (90° − i).', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('ec323b7b-5b68-51c6-972a-9254d17b0062', 'ce2d82de-fd4b-5292-9f1e-84aa27931530', 'يقف شخص طوله 1,7 m أمام مرآة مستوية عموديّة مثبّتة على جدار. ما أصغر ارتفاعٍ للمرآة يمكّنه من رؤية كامل قامته (من قدميه إلى رأسه)؟', '[{"id":"a","text":"0,85 m"},{"id":"b","text":"1,7 m"},{"id":"c","text":"1,2 m"},{"id":"d","text":"0,425 m"}]'::jsonb, 'a', 'بقانونَي الانعكاس وهندسة الصورة: الشعاع من القدمين ينعكس عند منتصف المسافة (قدم–عين)، والشعاع من الرأس ينعكس عند منتصف المسافة (عين–رأس)، فيكفي أن يغطّي طول المرآة نصف طول الشخص = 1,7/2 = 0,85 m (ولا يتعلّق ببُعده عن المرآة). ✓ الخطأ الشائع: ظنّ أنّ المرآة يجب أن تساوي طول الشخص كاملًا (1,7 m)؛ أو أخذ الرُّبع (0,425 m).', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('03c85167-c1ec-5a03-8442-15013bf2555c', 'ce2d82de-fd4b-5292-9f1e-84aa27931530', 'جسم نقطيّ A على بُعد 30 cm أمام مرآة مستوية. حُرِّكت المرآة مُبتعِدةً 10 cm عن الجسم (بقي الجسم مكانه). ما المسافة الجديدة بين الجسم A وصورته A′؟', '[{"id":"a","text":"80 cm"},{"id":"b","text":"60 cm"},{"id":"c","text":"100 cm"},{"id":"d","text":"20 cm"}]'::jsonb, 'a', 'الصورة في مرآة مستوية تقع خلفها على بُعدٍ يساوي بُعد الجسم أمامها. بعد الإبعاد صار بُعد الجسم عن المرآة 30 + 10 = 40 cm، فالصورة على 40 cm خلفها، والمسافة جسم–صورة = 40 + 40 = 80 cm. ✓ الخطأ الشائع: نسيان حركة المرآة (2 × 30 = 60 cm)؛ أو جمع الإزاحة مرّةً واحدة فقط.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('722ad6d4-2970-5fcc-903a-6c2091334aff', 'ce2d82de-fd4b-5292-9f1e-84aa27931530', 'يقترب شخص من مرآة مستوية ثابتة بسرعة 2 m/s. بأيّ سرعة تقترب صورتُه منه (المسافة بينه وبين صورته)؟', '[{"id":"a","text":"4 m/s"},{"id":"b","text":"2 m/s"},{"id":"c","text":"1 m/s"},{"id":"d","text":"0 m/s"}]'::jsonb, 'a', 'الصورة تبعد عن المرآة بمقدار بُعد الشخص عنها. حين يقترب الشخص من المرآة بمسافة d تقترب الصورة منها بالمسافة نفسها d، فتنقص المسافة جسم–صورة بمقدار 2d. إذن سرعة اقتراب الصورة من الشخص = 2 × 2 = 4 m/s. ✓ الخطأ الشائع: إعطاء سرعة الشخص نفسها (2 m/s) وإهمال أنّ الصورة تتحرّك أيضًا.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('e67d7f81-cd5a-52fa-9cce-e9e6b9c77418', 'ce2d82de-fd4b-5292-9f1e-84aa27931530', 'يسقط شعاع على المرآة الأولى من مرآتين مستويتين متوازيتين متقابلتين، فينعكس عليها ثمّ يسقط على الثانية وينعكس. ما اتجاه الشعاع الخارج بالنسبة إلى الشعاع الوارد الأوّل؟', '[{"id":"a","text":"موازٍ للشعاع الوارد (مع إزاحة جانبيّة)"},{"id":"b","text":"عموديّ على الشعاع الوارد"},{"id":"c","text":"معاكس تمامًا (يعود على نفس المسار)"},{"id":"d","text":"يصنع معه زاوية 45°"}]'::jsonb, 'a', 'لأنّ المرآتين متوازيتان، فناظماهما متوازيان، وبتطبيق قانون الانعكاس مرّتين يخرج الشعاع موازيًا لاتجاه وروده الأصليّ لكن مُزاحًا جانبيًّا. ✓ الخطأ الشائع: ظنّه معاكسًا (هذا يحصل في مرآتين متعامدتين 90°، لا متوازيتين)؛ أو عموديًّا.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('1da0695e-2e04-56bd-9f84-120f0b841b71', 'ba9daafc-27c7-5e69-aaaf-eb26f11fae73', 'svt', 'اختبار فهم الدرس', 1, 20, 5, 'quiz', 'admin', 0)
ON CONFLICT (id) DO UPDATE SET
  chapter_id = EXCLUDED.chapter_id,
