INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('1b6f08de-dd25-5cd5-9f6b-46ad4c851bb5', 'cfe8e5ad-8d29-5084-9e65-d6fb15aae2aa', 'شعاع ضوئي ينتقل من الماء إلى الهواء. أيّ العبارات صحيحة؟', '[{"id":"a","text":"ينكسر نحو الناظم لأنّ الهواء أكثر كثافة"},{"id":"b","text":"ينكسر بعيدًا عن الناظم لأنّ الهواء أقلّ كثافة بصرية"},{"id":"c","text":"لا ينكسر ويواصل مساره مستقيمًا"},{"id":"d","text":"ينعكس كلّيًّا دون نفاذ في جميع الأحوال"}]'::jsonb, 'b', 'عند الانتقال من الماء (أكثر كثافة بصرية) إلى الهواء (أقلّ كثافة)، ينكسر الشعاع بعيدًا عن الناظم، أي زاوية الانكسار أكبر من زاوية الورود.', 1)
