INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('b341e3ea-d1b3-5169-8076-a8dd68eb74e9', 'cfe8e5ad-8d29-5084-9e65-d6fb15aae2aa', 'جسم يقع بين البؤرة والعدسة المجمّعة (d < f). أيّ الصور التالية يعطيها هذا الجسم؟', '[{"id":"a","text":"صورة حقيقية مقلوبة مصغّرة"},{"id":"b","text":"صورة تخيّلية معتدلة مكبّرة"},{"id":"c","text":"صورة حقيقية مقلوبة مساوية"},{"id":"d","text":"لا تتكوّن أيّ صورة"}]'::jsonb, 'b', 'عندما يكون الجسم بين العدسة المجمّعة والبؤرة (d < f)، تتكوّن صورة تخيّلية في الجهة نفسها من الجسم، معتدلة (غير مقلوبة) ومكبّرة. هذا هو مبدأ العدسة المكبّرة.', 2)
