INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('d1ec52c7-8aaa-5f80-a11f-b5b11e512e04', 'cfe8e5ad-8d29-5084-9e65-d6fb15aae2aa', 'أيّ الشعاعَين التاليَين يواصل مساره دون انكسار عند مروره بالعدسة المجمّعة؟', '[{"id":"a","text":"الشعاع الموازي للمحور البصري"},{"id":"b","text":"الشعاع المارّ بالبؤرة F"},{"id":"c","text":"الشعاع المارّ بالمركز البصري O"},{"id":"d","text":"الشعاع العموديّ على المحور البصري"}]'::jsonb, 'c', 'الشعاع المارّ بالمركز البصري O للعدسة يواصل مساره دون أيّ انكسار؛ أمّا الشعاع الموازي للمحور فينكسر مارًّا بالبؤرة.', 3)
