INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('3be8161b-761a-5a62-a43a-fb96a0c3efb5', 'cfe8e5ad-8d29-5084-9e65-d6fb15aae2aa', 'في العين البشرية، أين تتكوّن صورة الأجسام التي ننظر إليها؟', '[{"id":"a","text":"على الشبكية (حقيقية مقلوبة)"},{"id":"b","text":"على قرنية العين"},{"id":"c","text":"أمام عدسة العين (تخيّلية)"},{"id":"d","text":"داخل العدسيّة نفسها"}]'::jsonb, 'a', 'عدسة العين (العدسيّة) تجمّع الأشعة وتكوّن صورة حقيقية مقلوبة على الشبكية. ثمّ يُعالج الدماغ هذه الصورة ويجعلها معتدلة في الإدراك.', 4)
