  ('709168e8-4fa2-5d35-8b5f-b75d803c0dcd', 'ba9daafc-27c7-5e69-aaaf-eb26f11fae73', 'svt', '👑 تحدّي النخبة: الانكسار والعدسات الرقيقة', 4, 300, 60, 'challenge', 'admin', 4)
