INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('78f8ccc7-474b-5ad1-a4ff-09e3f48cc444', 'a5969ea5-9f68-5e1b-80a6-31c44805a777', 'تحدث ظاهرة انكسار الضوء عندما:', '[{"id":"a","text":"يرتدّ الضوء عن سطح لامع"},{"id":"b","text":"ينتقل الضوء بميلٍ من وسط شفّاف إلى وسط شفّاف آخر مختلف"},{"id":"c","text":"يمرّ الضوء في وسط واحد متجانس"},{"id":"d","text":"ينطفئ المنبع الضوئي"}]'::jsonb, 'b', 'الانكسار هو انحراف الشعاع الضوئي عند عبوره بميلٍ من وسط شفّاف إلى آخر مختلف (مثل الهواء/الماء)، بسبب اختلاف سرعة الضوء في الوسطين. الارتداد عن السطح هو الانعكاس وليس الانكسار.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('2a7dad2e-662e-5c2e-af8b-684081aaa53e', 'a5969ea5-9f68-5e1b-80a6-31c44805a777', 'العدسة المجمّعة (المحدّبة) تتميّز بأنّها:', '[{"id":"a","text":"أنحف في الوسط منها عند الحافّتين"},{"id":"b","text":"أسمك في الوسط منها عند الحافّتين وتجمع الأشعّة المتوازية في البؤرة"},{"id":"c","text":"تشتّت الأشعّة المتوازية"},{"id":"d","text":"لا تغيّر مسار الضوء"}]'::jsonb, 'b', 'العدسة المجمّعة محدّبة، أسمك في وسطها، وتجمع حزمة الأشعّة المتوازية الواردة في نقطة واحدة هي البؤرة الرئيسية. أمّا العدسة المفرّقة فهي أنحف في الوسط وتشتّت الأشعّة.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('5b8f0ec1-0758-5f0d-bca1-675ff14f3d22', 'a5969ea5-9f68-5e1b-80a6-31c44805a777', 'عند مرور الضوء من الهواء إلى الماء بميل، فإنّ الشعاع المنكسر:', '[{"id":"a","text":"يبتعد عن الناظم"},{"id":"b","text":"يقترب من الناظم"},{"id":"c","text":"يبقى على نفس استقامة الشعاع الوارد"},{"id":"d","text":"يرتدّ إلى الهواء"}]'::jsonb, 'b', 'عند الانتقال من وسط أقلّ كثافة ضوئية (الهواء) إلى وسط أكثر كثافة (الماء) يقترب الشعاع المنكسر من الناظم (زاوية الانكسار أصغر من زاوية الورود). والعكس صحيح عند الخروج من الماء إلى الهواء.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('c48af3e8-0227-57ef-8492-5b5da0cdd753', 'a5969ea5-9f68-5e1b-80a6-31c44805a777', 'البُعد البؤري لعدسة مجمّعة هو المسافة بين:', '[{"id":"a","text":"حافّتي العدسة"},{"id":"b","text":"مركز العدسة والبؤرة الرئيسية"},{"id":"c","text":"الجسم والعدسة"},{"id":"d","text":"البؤرتين معًا"}]'::jsonb, 'b', 'البُعد البؤري f هو المسافة بين المركز البصري للعدسة وبؤرتها الرئيسية. كلّما صغر البُعد البؤري كانت العدسة أكثر تقاربًا (أكبر قدرة).', 4)
ON CONFLICT (id) DO UPDATE SET
