  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('8a48aeb6-e94a-5713-b2fc-345b1aa451c4', 'a5969ea5-9f68-5e1b-80a6-31c44805a777', 'قدرة العدسة المجمّعة C تُحسب بالعلاقة C = 1/f (وحدتها الديوبتر، وf بالمتر). إذا كان f = 0.5 m فما القدرة؟', '[{"id":"a","text":"0.5 ديوبتر"},{"id":"b","text":"5 ديوبتر"},{"id":"c","text":"2 ديوبتر"},{"id":"d","text":"50 ديوبتر"}]'::jsonb, 'c', 'C = 1/f = 1/0.5 = 2 ديوبتر. يجب التعبير عن f بالمتر قبل القسمة. الخطأ الشائع 0.5 يأتي من حساب f بدل 1/f.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('fc282b9e-2a29-57e0-8daf-2e9a482d82c1', 'a5969ea5-9f68-5e1b-80a6-31c44805a777', 'جسم موضوع على بُعد أكبر من ضِعف البُعد البؤري (أبعد من 2f) أمام عدسة مجمّعة. صورته تكون:', '[{"id":"a","text":"تخيّلية ومعتدلة ومكبّرة"},{"id":"b","text":"حقيقية ومقلوبة ومصغّرة"},{"id":"c","text":"حقيقية ومعتدلة ومماثلة"},{"id":"d","text":"غير موجودة"}]'::jsonb, 'b', 'عندما يكون الجسم أبعد من 2f عن عدسة مجمّعة، تتكوّن صورة حقيقية (تُستقبل على شاشة) مقلوبة ومصغّرة، تقع بين البؤرة و2f من الجهة الأخرى. هذا مبدأ عمل آلة التصوير والعين.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

