INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('d0494158-45a6-56f9-a3ec-b37520c91c96', '8b39c852-0c7b-55de-a62c-12473d3f639b', 'عدسة مجمّعة بُعدها البؤريّ f = 50 cm. ما قدرتها (فيرجانتها) C بالديوبتر؟', '[{"id":"a","text":"0,02 δ"},{"id":"b","text":"2 δ"},{"id":"c","text":"0,5 δ"},{"id":"d","text":"50 δ"}]'::jsonb, 'b', 'القدرة C = 1/f مع f بالأمتار. نحوّل: f = 50 cm = 0,5 m. إذن C = 1/0,5 = 2 δ. ✓ الخطأ الشائع: استعمال f بالسنتيمتر دون تحويل (1/50 = 0,02 δ)؛ أو قلب العلاقة (50 δ).', 1)
