INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('e8baffca-dc0e-5d20-a4d0-c4d57fbea720', '8b39c852-0c7b-55de-a62c-12473d3f639b', 'قال تلميذ: «عدسة بُعدها البؤريّ 25 cm قدرتها 25 δ». ما الخطأ؟', '[{"id":"a","text":"f بالأمتار: C = 1/0,25 = 4 δ"},{"id":"b","text":"C = 1/25 = 0,04 δ"},{"id":"c","text":"لا خطأ"},{"id":"d","text":"C = 2,5 δ"}]'::jsonb, 'a', 'القدرة C = 1/f مع f بالأمتار حصرًا: f = 25 cm = 0,25 m، إذن C = 1/0,25 = 4 δ (لا 25). (تمرين «صيد الخطأ».) الخطأ الشائع: استعمال القيمة العددية للبُعد البؤريّ بالسنتيمتر مباشرةً دون التحويل إلى الأمتار.', 2)
ON CONFLICT (id) DO UPDATE SET
