INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('14e9bc22-045d-5bf5-bdb5-da41f4359847', '8b39c852-0c7b-55de-a62c-12473d3f639b', 'عدسة مجمّعة f = 10 cm، وُضع أمامها جسم على البُعد OA = −15 cm. باستعمال علاقة المقرّبات 1/OA'' − 1/OA = 1/f، أوجد موضع الصورة OA''.', '[{"id":"a","text":"6 cm"},{"id":"b","text":"−30 cm"},{"id":"c","text":"30 cm"},{"id":"d","text":"15 cm"}]'::jsonb, 'c', 'من العلاقة: 1/OA'' = 1/f + 1/OA = 1/10 + 1/(−15) = 1/10 − 1/15 = 3/30 − 2/30 = 1/30. إذن OA'' = 30 cm (موجب ⟵ صورة حقيقية خلف العدسة). ✓ الخطأ الشائع: جمع 1/10 + 1/15 = 5/30 (نسيان إشارة OA السالبة) فيخرج OA'' = 6 cm.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('1fbca7bb-93af-506a-ae22-4bb14305fc83', '8b39c852-0c7b-55de-a62c-12473d3f639b', 'في الوضعية السابقة (f = 10 cm ; OA = −15 cm ; OA'' = +30 cm)، طول الجسم AB = 2 cm. ما طول الصورة A''B'' وطبيعتها؟ (التكبير γ = OA''/OA)', '[{"id":"a","text":"4 cm — مقلوبة"},{"id":"b","text":"4 cm — معتدلة"},{"id":"c","text":"1 cm — مقلوبة"},{"id":"d","text":"2 cm — مقلوبة"}]'::jsonb, 'a', 'التكبير γ = OA''/OA = 30/(−15) = −2. طول الصورة |A''B''| = |γ| × AB = 2 × 2 = 4 cm. وبما أنّ γ < 0 فالصورة مقلوبة. ✓ الخطأ الشائع: اعتبار الصورة معتدلة (γ سالب ⟵ مقلوبة دائمًا للصورة الحقيقية)؛ أو قلب النسبة γ = OA/OA'' فيخرج طول خاطئ.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('462924ff-3a03-569b-9c17-f2fa7a7e3166', '8b39c852-0c7b-55de-a62c-12473d3f639b', 'شعاع ضوئيّ ينتقل من الزجاج (n₁ = 1,5) إلى الهواء (n₂ = 1) بزاوية ورود i₁ = 30°. بقانون سنيل–ديكارت n₁ sin i₁ = n₂ sin i₂، ما قيمة sin i₂؟', '[{"id":"a","text":"0,33"},{"id":"b","text":"0,5"},{"id":"c","text":"1,5"},{"id":"d","text":"0,75"}]'::jsonb, 'd', 'sin i₂ = n₁ sin i₁ / n₂ = 1,5 × sin 30° / 1 = 1,5 × 0,5 / 1 = 0,75. (بما أنّ i₂ > i₁ فالشعاع يبتعد عن الناظم عند مروره إلى وسط أقلّ كثافة ضوئية — منطقيّ.) ✓ الخطأ الشائع: قلب النسبة sin i₂ = n₂ sin i₁ / n₁ = 0,33؛ أو إبقاء sin i₂ = sin i₁ = 0,5 (إهمال معاملَي الانكسار).', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('eff5e933-882c-50ce-8584-a603a5447f06', '8b39c852-0c7b-55de-a62c-12473d3f639b', 'جسم على البُعد OA = −30 cm أمام عدسة مجمّعة كوّن صورة حقيقية على البُعد OA'' = +60 cm. ما البُعد البؤريّ f للعدسة؟', '[{"id":"a","text":"90 cm"},{"id":"b","text":"20 cm"},{"id":"c","text":"45 cm"},{"id":"d","text":"10 cm"}]'::jsonb, 'b', 'من علاقة المقرّبات: 1/f = 1/OA'' − 1/OA = 1/60 − 1/(−30) = 1/60 + 1/30 = 1/60 + 2/60 = 3/60 = 1/20. إذن f = 20 cm. ✓ الخطأ الشائع: طرح 1/60 − 1/30 (إهمال إشارة OA السالبة) فيخرج f سالب أو خاطئ؛ أو جمع البُعدَين (90 cm).', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

