INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('26d1cfe6-94c3-5c57-aeec-d0c5388828e6', 'f431df6e-67d9-56e3-91f5-590546de1fca', 'أيّ الجمل التالية صحيحة حول النيوترون (N) في نموذج الذرّة؟', '[{"id":"a","text":"النيوترونات موجبة الشحنة وتوجد خارج النواة"},{"id":"b","text":"النيوترونات سالبة الشحنة وتدور حول النواة"},{"id":"c","text":"النيوترونات محايدة الشحنة وتوجد داخل النواة"},{"id":"d","text":"النيوترونات هي نفسها الإلكترونات"}]'::jsonb, 'c', 'النيوترونات جسيمات عديمة الشحنة (محايدة) توجد داخل نواة الذرّة إلى جانب البروتونات. أمّا الإلكترونات فسالبة وتدور خارج النواة.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('eb0a741b-59df-562f-8139-4e96e205790c', 'f431df6e-67d9-56e3-91f5-590546de1fca', 'جزيء CO₂ يحتوي على كربون وأكسجين. ما مجموع الذرّات فيه؟', '[{"id":"a","text":"ذرّتان"},{"id":"b","text":"4 ذرّات"},{"id":"c","text":"3 ذرّات"},{"id":"d","text":"ذرّة واحدة"}]'::jsonb, 'c', 'CO₂: ذرّة كربون واحدة (C) + ذرّتا أكسجين (O₂). المجموع = 1 + 2 = 3 ذرّات.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('b01b9503-2b8d-557b-9f97-a1e65a8f73bd', 'f431df6e-67d9-56e3-91f5-590546de1fca', 'ما مجموع الذرّات في جزيء H₂SO₄ (حمض الكبريتيك)؟', '[{"id":"a","text":"5 ذرّات"},{"id":"b","text":"6 ذرّات"},{"id":"c","text":"7 ذرّات"},{"id":"d","text":"8 ذرّات"}]'::jsonb, 'c', 'H₂SO₄: ذرّتا هيدروجين (H₂) + ذرّة كبريت (S) + 4 ذرّات أكسجين (O₄). المجموع = 2 + 1 + 4 = 7 ذرّات.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('38e8abd0-d72c-5095-882b-8b6512d67fb5', '4c10b91f-7bff-5a39-9b21-4f29a7f25d1c', 'svt', '👑 تحدّي النخبة: سرائر الذرّة والجزيء', 4, 300, 60, 'challenge', 'admin', 4)
ON CONFLICT (id) DO UPDATE SET
  chapter_id = EXCLUDED.chapter_id,
