INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('2cf38af4-b1e6-53f3-b571-1c5a066374eb', '3607d567-0e65-55d2-be84-36da8bee0154', 'تتكوّن الذرّة من:', '[{"id":"a","text":"نواة فقط"},{"id":"b","text":"إلكترونات فقط"},{"id":"c","text":"نواة مركزية موجبة تدور حولها إلكترونات سالبة"},{"id":"d","text":"نواة سالبة وإلكترونات موجبة"}]'::jsonb, 'c', 'تتكوّن الذرّة من نواة مركزية صغيرة موجبة الشحنة، تدور حولها إلكترونات سالبة الشحنة. الذرّة في مجملها متعادلة كهربائيًّا لأنّ عدد الشحنات الموجبة يساوي عدد الإلكترونات.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
