  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('e9112d6f-b475-5fc5-9bfe-53fc941cc39c', '3607d567-0e65-55d2-be84-36da8bee0154', 'رمز عنصر الأكسجين هو:', '[{"id":"a","text":"O"},{"id":"b","text":"Ox"},{"id":"c","text":"Au"},{"id":"d","text":"H"}]'::jsonb, 'a', 'رمز الأكسجين هو الحرف O. أمّا Au فرمز الذهب، وH رمز الهيدروجين. تُكتب رموز العناصر بحرف كبير واحد أو حرف كبير يتبعه حرف صغير.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('d1743703-1908-5e15-bc4c-26e1af720a68', '3607d567-0e65-55d2-be84-36da8bee0154', 'الفرق الأساسي بين الذرّة والجزيء هو أنّ الجزيء:', '[{"id":"a","text":"أصغر من الذرّة دائمًا"},{"id":"b","text":"مجموعة من ذرّتين أو أكثر مترابطة معًا"},{"id":"c","text":"هو نفسه الذرّة بتسمية أخرى"},{"id":"d","text":"لا يحتوي على ذرّات"}]'::jsonb, 'b', 'الجزيء هو تجمّع لذرّتين أو أكثر مترابطة فيما بينها (قد تكون من نفس العنصر مثل O₂، أو من عناصر مختلفة مثل H₂O). أمّا الذرّة فهي أصغر وحدة بنائية للعنصر.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('4491c581-b572-54e5-9394-a88842a92207', '3607d567-0e65-55d2-be84-36da8bee0154', 'كم عدد الذرّات الكلّي في جزيء حمض الكبريتيك H₂SO₄؟', '[{"id":"a","text":"3 ذرّات"},{"id":"b","text":"6 ذرّات"},{"id":"c","text":"7 ذرّات"},{"id":"d","text":"4 ذرّات"}]'::jsonb, 'c', 'نجمع الأرقام السفلية لكلّ عنصر: هيدروجين H₂ = 2، كبريت S = 1، أكسجين O₄ = 4. المجموع = 2 + 1 + 4 = 7 ذرّات. الرقم 3 خطأ شائع من عدّ أنواع العناصر بدل الذرّات.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('658fd900-dfb8-516e-8bff-51650f27fe16', '3607d567-0e65-55d2-be84-36da8bee0154', 'الصيغة 3 H₂O تعني:', '[{"id":"a","text":"جزيء ماء واحد فيه 3 ذرّات أكسجين"},{"id":"b","text":"ثلاثة جزيئات ماء، أي 6 ذرّات هيدروجين و3 ذرّات أكسجين"},{"id":"c","text":"3 ذرّات هيدروجين فقط"},{"id":"d","text":"جزيء واحد فيه 32 ذرّة"}]'::jsonb, 'b', 'المُعامِل 3 أمام الصيغة يدلّ على عدد الجزيئات: 3 جزيئات ماء. كلّ جزيء H₂O فيه 2 هيدروجين و1 أكسجين، فالمجموع: 3×2 = 6 ذرّات هيدروجين و3×1 = 3 ذرّات أكسجين.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('ef1a6381-2aaa-50dc-89a0-bc8ea056f2f9', '3607d567-0e65-55d2-be84-36da8bee0154', 'أيّ مما يلي يمثّل جسمًا بسيطًا (مكوّنًا من نوع واحد من الذرّات)؟', '[{"id":"a","text":"الماء H₂O"},{"id":"b","text":"ثنائي أكسيد الكربون CO₂"},{"id":"c","text":"غاز ثنائي الأكسجين O₂"},{"id":"d","text":"كلور الصوديوم NaCl"}]'::jsonb, 'c', 'الجسم البسيط يتكوّن من نوع واحد فقط من العناصر؛ غاز ثنائي الأكسجين O₂ مكوّن من ذرّتي أكسجين من نفس النوع. أمّا H₂O وCO₂ وNaCl فأجسام مركّبة لاحتوائها على عناصر مختلفة.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

