INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('281d8628-4da5-5586-8ce3-59fc397b9904', '34d0ec99-e8cb-5a8a-b767-4f0c6e78fe96', 'ذرّة الصوديوم متعادلة كهربائيًّا وتحتوي على 11 بروتونًا و11 إلكترونًا. فقدت إلكترونًا واحدًا فتحوّلت إلى أيون. ما شحنة الأيون الناتج؟', '[{"id":"a","text":"+1"},{"id":"b","text":"−1"},{"id":"c","text":"+11"},{"id":"d","text":"0"}]'::jsonb, 'a', 'الشحنة تنتج من الفرق بين عدد البروتونات (موجبة) وعدد الإلكترونات (سالبة). بعد فقد إلكترون يصبح عدد الإلكترونات 10 مقابل 11 بروتونًا، فيزيد بروتونٌ واحد غير معادَل: الشحنة = +1 (أيون موجب Na⁺). ✓ الخطأ الشائع: ظنّ أنّ فقد إلكترونٍ يمنح شحنةً سالبة (−1) — العكس هو الصحيح: فقد سالبٍ يترك المجموع موجبًا.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('025f0487-dc8b-535a-aa8f-3b286ee44329', '34d0ec99-e8cb-5a8a-b767-4f0c6e78fe96', 'قال تلميذ: «الصيغة H₂O تعني وجود جزيئَين من الهيدروجين وذرّة أكسجين». ما الخطأ؟', '[{"id":"a","text":"الرقم 2 يدلّ على ذرّتَي هيدروجين (لا جزيئَين) مرتبطتَين بذرّة أكسجين في جزيء ماء واحد"},{"id":"b","text":"لا خطأ، التفسير صحيح"},{"id":"c","text":"الصيغة تعني ذرّتَي أكسجين وذرّة هيدروجين"},{"id":"d","text":"الرقم 2 يدلّ على جزيئَين من الماء"}]'::jsonb, 'a', 'الدليل 2 أسفل H يدلّ على عدد ذرّات العنصر داخل الجزيء الواحد: جزيء الماء يتكوّن من ذرّتَي هيدروجين وذرّة أكسجين واحدة مرتبطة معًا — لا «جزيئين» من الهيدروجين. (تمرين «صيد الخطأ».) الخطأ الشائع: الخلط بين الذرّة والجزيء، وبين الدليل داخل الصيغة والمعامل أمامها.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('6f6f1b65-c14a-5704-ad58-45bd37d15ab6', '34d0ec99-e8cb-5a8a-b767-4f0c6e78fe96', 'عيّنة من الماء H₂O كتلتها 36 g، والكتلة المولية M(H₂O) = 18 g/mol. كم مولًا من جزيئات الماء تحتوي العيّنة، وكم مولًا من ذرّات الهيدروجين؟', '[{"id":"a","text":"2 mol جزيء ; 4 mol ذرّات H"},{"id":"b","text":"2 mol جزيء ; 2 mol ذرّات H"},{"id":"c","text":"0,5 mol جزيء ; 1 mol ذرّات H"},{"id":"d","text":"18 mol جزيء ; 36 mol ذرّات H"}]'::jsonb, 'a', 'عدد مولات الجزيئات: n = m/M = 36/18 = 2 mol. وبما أنّ كلّ جزيء ماء يحوي ذرّتَي هيدروجين، فعدد مولات ذرّات H = 2 × 2 = 4 mol. ✓ الخطأ الشائع: نسيان ضرب عدد ذرّات H في المول (فيبقى 2 mol)؛ أو قلب العلاقة n = M/m (فيخرج 0,5 mol).', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('fe136c71-d3eb-5f13-a6f6-54f7e9831667', '34d0ec99-e8cb-5a8a-b767-4f0c6e78fe96', 'في الكتابة الكيميائية 2 Ca₃(PO₄)₂، كم ذرّة أكسجين (O) في المجموع؟ (الرقم 2 خارج القوسَين يضرب ما بداخلهما، والمعامل 2 في البداية يضرب الصيغة كلّها.)', '[{"id":"a","text":"16"},{"id":"b","text":"8"},{"id":"c","text":"4"},{"id":"d","text":"12"}]'::jsonb, 'a', 'داخل جزيء واحد Ca₃(PO₄)₂: عدد ذرّات O = 4 (داخل القوس) × 2 (الدليل خارج القوس) = 8 ذرّات. ثمّ نضرب في المعامل 2 (عدد الجزيئات): 8 × 2 = 16 ذرّة أكسجين. ✓ الخطأ الشائع: نسيان المعامل 2 في البداية (فيبقى 8)؛ أو أخذ 4 (داخل القوس فقط دون الدليل)؛ أو الخلط بين المعامل والدليل.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('d2db203a-d19c-50ce-8739-f9e9ecf3b3c5', '34d0ec99-e8cb-5a8a-b767-4f0c6e78fe96', 'احسب الكتلة المولية لكربونات الكالسيوم CaCO₃. المعطى: M(Ca) = 40 ; M(C) = 12 ; M(O) = 16 (g/mol).', '[{"id":"a","text":"100 g/mol"},{"id":"b","text":"68 g/mol"},{"id":"c","text":"52 g/mol"},{"id":"d","text":"116 g/mol"}]'::jsonb, 'a', 'الصيغة CaCO₃ تحوي ذرّة Ca وذرّة C وثلاث ذرّات O: M = 40 + 12 + (3 × 16) = 40 + 12 + 48 = 100 g/mol. ✓ الخطأ الشائع: حساب ذرّة أكسجين واحدة فقط (40 + 12 + 16 = 68)؛ أو إهمال الأكسجين (40 + 12 = 52)؛ أو ضرب O في 4 (40 + 12 + 64 = 116).', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('b16d8be2-2796-5a12-b7cb-d18700b01f41', '34d0ec99-e8cb-5a8a-b767-4f0c6e78fe96', 'خليطٌ غازيّ مكوّن من جزيئَين من ثنائي الأكسجين O₂ وثلاثة جزيئات من ثنائي أكسيد الكربون CO₂. كم ذرّة أكسجين (O) في هذا الخليط؟', '[{"id":"a","text":"10"},{"id":"b","text":"5"},{"id":"c","text":"8"},{"id":"d","text":"13"}]'::jsonb, 'a', 'من O₂: كلّ جزيء فيه ذرّتا أكسجين، و2 جزيء تعطي 2 × 2 = 4 ذرّات O. ومن CO₂: كلّ جزيء فيه ذرّتا أكسجين، و3 جزيئات تعطي 3 × 2 = 6 ذرّات O. المجموع = 4 + 6 = 10 ذرّات أكسجين. ✓ الخطأ الشائع: عدّ الجزيئات لا الذرّات (2 + 3 = 5)؛ أو إهمال ذرّات أكسجين O₂.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('887a72dd-e999-5b85-85b3-611050765028', '4dffb31a-ec0d-5def-90db-3ab72e4936d7', 'svt', 'اختبار فهم الدرس', 1, 20, 5, 'quiz', 'admin', 0)
ON CONFLICT (id) DO UPDATE SET
  chapter_id = EXCLUDED.chapter_id,
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  difficulty = EXCLUDED.difficulty,
  xp_reward = EXCLUDED.xp_reward,
  reward_coins = EXCLUDED.reward_coins,
  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('c687b5ae-4a3f-5a77-8f52-feb83e25dda8', '887a72dd-e999-5b85-85b3-611050765028', 'ما تعريف التفاعل الكيميائي؟', '[{"id":"a","text":"تغيير حالة المادّة من صلبة إلى سائلة دون تغيير طبيعتها"},{"id":"b","text":"تحوّل تختفي خلاله موادّ (المتفاعلات) وتتكوّن موادّ جديدة (النواتج) لها خصائص مختلفة"},{"id":"c","text":"انتشار مادّة في أخرى دون أي تغيير كيميائي"},{"id":"d","text":"تغيّر شكل جسم ما مع بقاء تركيبه الكيميائي"}]'::jsonb, 'b', 'التفاعل الكيميائي هو تحوّل كيميائي تختفي خلاله موادّ تُسمّى المتفاعلات وتنتج موادّ جديدة ذات خصائص مختلفة تُسمّى النواتج.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('73fd748f-4a38-57a5-9e17-b9c62963e4d3', '887a72dd-e999-5b85-85b3-611050765028', 'ماذا ينصّ قانون انحفاظ الكتلة (لافوازييه)؟', '[{"id":"a","text":"كتلة النواتج دائمًا أكبر من كتلة المتفاعلات"},{"id":"b","text":"كتلة المتفاعلات دائمًا أكبر من كتلة النواتج"},{"id":"c","text":"كتلة المتفاعلات تساوي كتلة النواتج في التفاعل الكيميائي"},{"id":"d","text":"الكتلة تختفي جزئيًّا أثناء التفاعل الكيميائي"}]'::jsonb, 'c', 'ينصّ قانون لافوازييه على انحفاظ الكتلة: كتلة المتفاعلات = كتلة النواتج. فلا شيء يُفقَد ولا شيء يُخلَق، كلّ شيء يتحوّل.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('95f04cfb-fc30-5317-a00a-ad2938f3b265', '887a72dd-e999-5b85-85b3-611050765028', 'ما الفرق بين التحوّل الفيزيائي والتحوّل الكيميائي؟', '[{"id":"a","text":"التحوّل الفيزيائي يُنتج موادًّا جديدة والكيميائي لا يغيّر طبيعة المادّة"},{"id":"b","text":"التحوّل الفيزيائي يتغيّر فيه الشكل أو الحالة دون تغيير طبيعة المادّة، أمّا الكيميائي فتظهر فيه موادّ جديدة"},{"id":"c","text":"كلاهما متطابقان في النتيجة"},{"id":"d","text":"التحوّل الكيميائي يشمل ذوبان الجليد وتبخّر الماء"}]'::jsonb, 'b', 'في التحوّل الفيزيائي (كذوبان الجليد أو تبخّر الماء) تتغيّر الحالة أو الشكل دون تغيير طبيعة المادّة. أمّا في التحوّل الكيميائي (كاحتراق الورق أو صدأ الحديد) فتظهر موادّ جديدة.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('b23d29b0-9449-51de-8291-a8a59fd70933', '887a72dd-e999-5b85-85b3-611050765028', 'لماذا يجب موازنة المعادلة الكيميائية بتغيير المعاملات فقط؟', '[{"id":"a","text":"لأنّ تغيير الأرقام السفلية يُغيّر طبيعة المركّب ويُخالف انحفاظ الكتلة"},{"id":"b","text":"لأنّ المعاملات تجعل المعادلة أجمل مظهرًا"},{"id":"c","text":"لأنّ المعاملات تُغيّر طبيعة المواد المتفاعلة"},{"id":"d","text":"لا يوجد سبب علمي لذلك"}]'::jsonb, 'a', 'نوازن المعادلة بتغيير المعاملات أمام الصيغ دون تغيير الأرقام السفلية داخلها، لأنّ تغيير الأرقام السفلية يُغيّر طبيعة المركّب ذاته ويُنتج مواد وهمية غير موجودة.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('d421aa28-cfb5-54ae-b986-765a29301f0e', '887a72dd-e999-5b85-85b3-611050765028', 'في المعادلة الموزونة: CH₄ + 2O₂ → CO₂ + 2H₂O، كم ذرّة أكسجين يوجد في طرف النواتج؟', '[{"id":"a","text":"ذرّتان"},{"id":"b","text":"ثلاث ذرّات"},{"id":"c","text":"أربع ذرّات"},{"id":"d","text":"ست ذرّات"}]'::jsonb, 'c', 'في طرف النواتج: CO₂ يحتوي ذرّتَي أكسجين + 2H₂O يحتويان ذرّتَي أكسجين = 4 ذرّات أكسجين. هذا يتوافق مع طرف المتفاعلات: 2O₂ = 4 ذرّات أكسجين، وهو ما يُثبت انحفاظ الكتلة.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('07576f0b-3c33-598e-80e6-79b3ce4364ab', '4dffb31a-ec0d-5def-90db-3ab72e4936d7', 'svt', 'تمرين: المتفاعلات والنواتج وانحفاظ الكتلة', 2, 60, 12, 'practice', 'admin', 1)
ON CONFLICT (id) DO UPDATE SET
  chapter_id = EXCLUDED.chapter_id,
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  difficulty = EXCLUDED.difficulty,
  xp_reward = EXCLUDED.xp_reward,
  reward_coins = EXCLUDED.reward_coins,
  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('1f6bacee-755c-5a84-97c4-6cfeb4a30a7d', '07576f0b-3c33-598e-80e6-79b3ce4364ab', 'في التفاعل: C + O₂ → CO₂، ما هي المتفاعلات؟', '[{"id":"a","text":"CO₂ فقط"},{"id":"b","text":"C و CO₂"},{"id":"c","text":"O₂ و CO₂"},{"id":"d","text":"C و O₂"}]'::jsonb, 'd', 'في المعادلة الكيميائية يفصل السهم بين الموادّ الداخلة في التفاعل (المتفاعلات) على يساره والموادّ المتكوّنة (النواتج) على يمينه. هنا الكربون C والأكسجين O₂ على يسار السهم فهما المتفاعلان اللذان يستهلكان، وثاني أكسيد الكربون CO₂ على يمينه فهو الناتج المتكوّن من اتّحادهما.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('55175f89-37f1-5093-be10-635d8cf97a74', '07576f0b-3c33-598e-80e6-79b3ce4364ab', 'أيّ ممّا يلي تحوّل فيزيائي؟', '[{"id":"a","text":"احتراق الورق"},{"id":"b","text":"صدأ الحديد"},{"id":"c","text":"ذوبان الجليد"},{"id":"d","text":"احتراق الميثان"}]'::jsonb, 'c', 'في ذوبان الجليد تتغيّر الحالة الفيزيائية فقط من الصلبة إلى السائلة، لكنّ المادّة تبقى ماءً (H₂O) ولا تتكوّن مادّة جديدة، لذا فهو تحوّل فيزيائي قابل للعكس بالتجميد. أمّا احتراق الورق أو الميثان وصدأ الحديد فتظهر فيها موادّ جديدة مختلفة الخصائص، فهي تحوّلات كيميائية.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('192af321-7e53-5849-900d-cb4c1814f863', '07576f0b-3c33-598e-80e6-79b3ce4364ab', 'ماذا ينصّ قانون انحفاظ الكتلة (لافوازييه)؟', '[{"id":"a","text":"كتلة المتفاعلات = كتلة النواتج"},{"id":"b","text":"كتلة المتفاعلات أكبر من كتلة النواتج"},{"id":"c","text":"كتلة المتفاعلات أصغر من كتلة النواتج"},{"id":"d","text":"تختفي الكتلة أثناء التفاعل"}]'::jsonb, 'a', 'قانون لافوازييه: «لا شيء يُفقَد ولا شيء يُخلَق، كلّ شيء يتحوّل». فأثناء التفاعل لا تختفي الذرّات بل تعيد ترتيب روابطها فقط، لذا يبقى عددها ونوعها ثابتَين، ومن ثَمّ يكون مجموع كتل المتفاعلات مساويًا تمامًا لمجموع كتل النواتج.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('ea79b802-7f5c-5f15-99a8-70d5c96b57b7', '07576f0b-3c33-598e-80e6-79b3ce4364ab', 'تفاعل 4 g من الميثان مع 16 g من الأكسجين تفاعلًا تامًّا. ما كتلة النواتج؟', '[{"id":"a","text":"20 g"},{"id":"b","text":"12 g"},{"id":"c","text":"16 g"},{"id":"d","text":"4 g"}]'::jsonb, 'a', 'بما أنّ التفاعل تامّ، تُستهلك المتفاعلات كاملةً. وبتطبيق قانون انحفاظ الكتلة (كتلة النواتج = كتلة المتفاعلات): كتلة النواتج = 4 g (ميثان) + 16 g (أكسجين) = 20 g.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('53586353-b2ea-5962-8d4e-863c37d7367c', '07576f0b-3c33-598e-80e6-79b3ce4364ab', 'أيّ ممّا يلي مؤشّر على حدوث تفاعل كيميائي؟', '[{"id":"a","text":"انطلاق غاز أو تغيّر اللون وتكوّن مادّة جديدة"},{"id":"b","text":"تغيّر شكل المادّة فقط"},{"id":"c","text":"تغيّر درجة الحرارة دون تغيّر المادّة"},{"id":"d","text":"تبخّر الماء"}]'::jsonb, 'a', 'ظهور مادّة جديدة يصاحبه غالبًا انطلاق غاز أو تغيّر لون أو تكوّن راسب، وهي مؤشّرات على تفاعل كيميائي.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('8a56a677-e9ad-5b29-a153-45ba0e93741f', '07576f0b-3c33-598e-80e6-79b3ce4364ab', 'كم عدد ذرّات الأكسجين في 2H₂O؟', '[{"id":"a","text":"2"},{"id":"b","text":"4"},{"id":"c","text":"1"},{"id":"d","text":"3"}]'::jsonb, 'a', 'كلّ جزيء ماء يحتوي ذرّة أكسجين واحدة، و2H₂O يعني جزيئين، أي 2 × 1 = 2 ذرّة أكسجين.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('107c0650-6e11-5652-b548-d850f77b6e0a', '4dffb31a-ec0d-5def-90db-3ab72e4936d7', 'svt', '⚔️ زعيم الفصل: موازنة المعادلات', 3, 120, 30, 'boss', 'admin', 2)
ON CONFLICT (id) DO UPDATE SET
