  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('da0e4132-a709-5103-a2a2-616b6cbf3d8f', '39a24d45-61d7-5aaf-b4c2-7ac9958ff4cd', 'في تفاعل كيميائي، تُسمّى المواد الموجودة قبل التفاعل:', '[{"id":"a","text":"النواتج"},{"id":"b","text":"المتفاعلات"},{"id":"c","text":"الرواسب"},{"id":"d","text":"المحفّزات"}]'::jsonb, 'b', 'المتفاعلات هي المواد الابتدائية الموجودة قبل التفاعل (يسار المعادلة)، وتتحوّل أثناء التفاعل إلى نواتج (يمين المعادلة). السهم يفصل بينهما ويتّجه من المتفاعلات إلى النواتج.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('1852ee76-c415-5e62-8d5b-ad4aec32c0e3', '39a24d45-61d7-5aaf-b4c2-7ac9958ff4cd', 'ينصّ قانون انحفاظ الكتلة (لافوازييه) على أنّ كتلة المتفاعلات:', '[{"id":"a","text":"أكبر من كتلة النواتج"},{"id":"b","text":"أصغر من كتلة النواتج"},{"id":"c","text":"تساوي كتلة النواتج"},{"id":"d","text":"تختفي تمامًا بعد التفاعل"}]'::jsonb, 'c', 'أثناء التفاعل الكيميائي تُحفظ الكتلة: مجموع كتل المتفاعلات = مجموع كتل النواتج، لأنّ الذرّات لا تُستحدث ولا تُفنى بل يُعاد ترتيبها فقط. لذلك يجب أن تُوازن المعادلة.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('42fdbcbf-b3fc-5657-8bb9-cce796f0f4ef', '39a24d45-61d7-5aaf-b4c2-7ac9958ff4cd', 'تفاعَل 8 g من الكبريت مع كمّية من الحديد فتشكّل 22 g من كبريتور الحديد دون فائض. ما كتلة الحديد المتفاعل؟', '[{"id":"a","text":"30 g"},{"id":"b","text":"14 g"},{"id":"c","text":"22 g"},{"id":"d","text":"8 g"}]'::jsonb, 'b', 'بتطبيق انحفاظ الكتلة: كتلة الحديد + كتلة الكبريت = كتلة الناتج، أي m(Fe) + 8 = 22، إذن m(Fe) = 22 − 8 = 14 g. الخطأ 30 g ناتج عن الجمع بدل الطرح.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('5fefc337-05c5-5e42-aae6-4e89380875d1', '39a24d45-61d7-5aaf-b4c2-7ac9958ff4cd', 'أيّ مما يلي دليلٌ على حدوث تفاعل كيميائي وليس مجرّد تغيّر فيزيائي؟', '[{"id":"a","text":"ذوبان الجليد إلى ماء"},{"id":"b","text":"تكوّن غاز جديد وتغيّر اللون وانطلاق حرارة"},{"id":"c","text":"تبخّر الماء بالتسخين"},{"id":"d","text":"تكسير قطعة طبشور"}]'::jsonb, 'b', 'التفاعل الكيميائي يصاحبه ظهور مواد جديدة بخصائص مختلفة (انطلاق غاز، تغيّر لون، تكوّن راسب، انطلاق أو امتصاص حرارة). أمّا الذوبان والتبخّر والتكسير فتغيّرات فيزيائية لا تنشأ عنها مادّة جديدة.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('e7a0882e-4530-56b6-92c1-c41e43f7ec12', '39a24d45-61d7-5aaf-b4c2-7ac9958ff4cd', 'ما المعامل الصحيح الذي يُوازن معادلة احتراق غاز الهيدروجين: ... H₂ + O₂ → 2 H₂O ؟ (المطلوب المعامل أمام H₂)', '[{"id":"a","text":"1"},{"id":"b","text":"3"},{"id":"c","text":"2"},{"id":"d","text":"4"}]'::jsonb, 'c', 'المعادلة الموزونة: 2 H₂ + O₂ → 2 H₂O. على اليمين 4 ذرّات H و2 ذرّة O، فنحتاج 2 H₂ (=4 H) و O₂ (=2 O) على اليسار. إذن المعامل أمام H₂ هو 2.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('b1770b50-0636-5e1a-8362-994a9bd40cd8', '39a24d45-61d7-5aaf-b4c2-7ac9958ff4cd', 'في المعادلة الموزونة C + O₂ → CO₂، إذا تفاعل 12 g من الكربون مع 32 g من ثنائي الأكسجين، فما كتلة ثنائي أكسيد الكربون الناتج؟', '[{"id":"a","text":"20 g"},{"id":"b","text":"44 g"},{"id":"c","text":"32 g"},{"id":"d","text":"12 g"}]'::jsonb, 'b', 'حسب انحفاظ الكتلة: كتلة CO₂ = كتلة C + كتلة O₂ = 12 + 32 = 44 g. الكتلة لا تضيع، بل كلّ ذرّات الكربون والأكسجين انتقلت إلى الناتج.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('748e99c9-315e-510b-a01d-03068a57ddd2', '4dffb31a-ec0d-5def-90db-3ab72e4936d7', 'svt', '👑 تحدّي المناظرة ⭐⭐⭐⭐: التفاعل الكيميائي وحفظ الكتلة — استدلال متقدّم', 4, 300, 60, 'challenge', 'admin', 6)
ON CONFLICT (id) DO UPDATE SET
  chapter_id = EXCLUDED.chapter_id,
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  difficulty = EXCLUDED.difficulty,
  xp_reward = EXCLUDED.xp_reward,
  reward_coins = EXCLUDED.reward_coins,
  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('dddc702e-b3ff-5f82-86d4-73bcc3f38eb0', '748e99c9-315e-510b-a01d-03068a57ddd2', 'في تفاعل A + B → C، تفاعل 8 g من A مع 12 g من B تفاعلًا تامًّا. ما كتلة الناتج C؟', '[{"id":"a","text":"4 g"},{"id":"b","text":"20 g"},{"id":"c","text":"8 g"},{"id":"d","text":"96 g"}]'::jsonb, 'b', 'بمبدأ حفظ الكتلة (قانون لافوازييه): كتلة النواتج = كتلة المتفاعلات. إذن m(C) = 8 + 12 = 20 g. ✓ الخطأ الشائع: طرح الكتلتَين (12 − 8 = 4) أو ضربهما (96) — الكتلة تُحفَظ فتُجمَع كتل المتفاعلات.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('9b74d777-1103-58df-b825-cd2089a3ca50', '748e99c9-315e-510b-a01d-03068a57ddd2', 'لموازنة H₂ + O₂ → H₂O كتب تلميذ: «H₂ + O₂ → H₂O₂ لموازنة ذرّات الأكسجين». ما الخطأ؟', '[{"id":"a","text":"لا تُغيَّر الصيغ بل المعاملات: 2H₂ + O₂ → 2H₂O"},{"id":"b","text":"الصواب H₂ + O₂ → H₂O دون تغيير"},{"id":"c","text":"لا خطأ، H₂O₂ صحيحة"},{"id":"d","text":"الصواب H₂ + 2O₂ → H₂O"}]'::jsonb, 'a', 'الموازنة تُعدِّل المعاملات (الأعداد أمام الصيغ) لا الصيغ نفسها: تغيير H₂O إلى H₂O₂ يغيّر المادّة (ماء أكسجينيّ لا ماء). الموازنة الصحيحة: 2H₂ + O₂ → 2H₂O. (تمرين «صيد الخطأ».) الخطأ الشائع: تغيير الدلائل (indices) بدل المعاملات.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('5fc3e193-0add-5bbd-a1ef-52f51bda8840', '748e99c9-315e-510b-a01d-03068a57ddd2', 'وفق 2H₂ + O₂ → 2H₂O، نحصل على 36 g من الماء انطلاقًا من 4 g من H₂. ما كتلة الأكسجين O₂ المستهلكة؟', '[{"id":"a","text":"40 g"},{"id":"b","text":"36 g"},{"id":"c","text":"16 g"},{"id":"d","text":"32 g"}]'::jsonb, 'd', 'بحفظ الكتلة: m(H₂) + m(O₂) = m(H₂O)، إذن m(O₂) = m(H₂O) − m(H₂) = 36 − 4 = 32 g. ✓ الخطأ الشائع: جمع الكتلتَين (36 + 4 = 40) بدل طرحهما؛ حفظ الكتلة يعني أنّ كتلة المتفاعلَين معًا تساوي كتلة الماء.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('f4ccfb1b-7c60-560a-b6fa-466f53ad6cf6', '748e99c9-315e-510b-a01d-03068a57ddd2', 'ما معامل O₂ في الموازنة الصحيحة للمعادلة: C₃H₈ + O₂ → CO₂ + H₂O؟', '[{"id":"a","text":"3"},{"id":"b","text":"4"},{"id":"c","text":"5"},{"id":"d","text":"7"}]'::jsonb, 'c', 'الموازنة: C₃H₈ + 5O₂ → 3CO₂ + 4H₂O. التحقّق: الكربون 3 = 3 ✓ ؛ الهيدروجين 8 = 4×2 ✓ ؛ الأكسجين في النواتج 3×2 + 4×1 = 10 = 5×2 ✓. إذن معامل O₂ هو 5. الخطأ الشائع: موازنة الكربون والهيدروجين فقط ونسيان جمع ذرّات الأكسجين في الناتجَين معًا (CO₂ وH₂O).', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('8956dc86-2fad-5451-bf12-217f3a3e29ad', '748e99c9-315e-510b-a01d-03068a57ddd2', 'وفق S + O₂ → SO₂، أُحرق 64 g من الكبريت تفاعلًا تامًّا. الكتل المولية: M(S) = 32 g/mol، M(SO₂) = 64 g/mol. ما كتلة ثاني أكسيد الكبريت SO₂ الناتجة؟', '[{"id":"a","text":"128 g"},{"id":"b","text":"64 g"},{"id":"c","text":"32 g"},{"id":"d","text":"96 g"}]'::jsonb, 'a', 'عدد مولات الكبريت: n(S) = 64/32 = 2 mol. حسب المعادلة، كلّ مول من S يعطي مولًا من SO₂، إذن n(SO₂) = 2 mol. الكتلة: m(SO₂) = n × M = 2 × 64 = 128 g. ✓ (تحقّق بحفظ الكتلة: m(O₂) = 128 − 64 = 64 g، أي 2 mol من O₂). الخطأ الشائع: إعطاء 64 g (كتلة الكبريت نفسها) أو الخلط في عدد المولات.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('6497d532-e9b6-5785-b180-8129e661208f', '748e99c9-315e-510b-a01d-03068a57ddd2', 'وفق CH₄ + 2O₂ → CO₂ + 2H₂O، احترق 16 g من CH₄ مع 64 g من O₂ فنتج 44 g من CO₂. ما كتلة الماء H₂O الناتجة؟', '[{"id":"a","text":"44 g"},{"id":"b","text":"80 g"},{"id":"c","text":"36 g"},{"id":"d","text":"16 g"}]'::jsonb, 'c', 'بحفظ الكتلة: كتلة المتفاعلات = 16 + 64 = 80 g = كتلة النواتج (CO₂ + H₂O). إذن m(H₂O) = 80 − 44 = 36 g. ✓ (تحقّق: 36 g ماء = 2 mol × 18 g/mol، متوافق مع المعادلة). الخطأ الشائع: إهمال أحد المتفاعلَين في المجموع؛ أو الخلط بين كتلة CO₂ وكتلة الماء.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

