INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('55e16890-ab5d-56d6-b33a-6048d53a5cdf', 'e5ca2d8d-4123-5574-90f6-a5c907c89481', 'محلول A له pH = 9 ومحلول B له pH = 2. أيّ العبارات صحيحة؟', '[{"id":"a","text":"كلاهما حمضي"},{"id":"b","text":"A حمضي و B قاعدي"},{"id":"c","text":"كلاهما متعادل"},{"id":"d","text":"A قاعدي و B حمضي"}]'::jsonb, 'd', 'pH = 9 أكبر من 7 إذن A قاعدي؛ pH = 2 أصغر من 7 إذن B حمضي. هذا هو التصنيف الصحيح وفق مقياس pH.', 1)
ON CONFLICT (id) DO UPDATE SET
