  reward_coins = EXCLUDED.reward_coins,
  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('a258933c-bffe-5d2d-b701-9a1c094e652b', 'fd002b29-306a-58a8-a501-5505114cf8fe', 'محلول حمضيّ pH = 2، خُفِّف بالماء 10 مرّات. ما قيمة pH التقريبية بعد التخفيف؟', '[{"id":"a","text":"1"},{"id":"b","text":"3"},{"id":"c","text":"2"},{"id":"d","text":"5"}]'::jsonb, 'b', 'تخفيف محلول حمضيّ بعامل 10 يرفع pH بمقدار وحدة واحدة نحو 7 (يصبح أقلّ حمضيّة): 2 + 1 = 3. ✓ الخطأ الشائع: ظنّ أنّ إضافة الماء تُنقص pH (فيخرج 1) — التخفيف يُقرّب pH من 7 دائمًا، لا يبعده.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('98b445a8-3a43-5cf7-9f9b-2fc09d38040e', 'fd002b29-306a-58a8-a501-5505114cf8fe', 'قال تلميذ: «عند إضافة الماء إلى حمض، ينقص pH لأنّ كميّة السائل تزداد». ما الخطأ؟', '[{"id":"a","text":"التخفيف يرفع pH الحمض نحو 7 (لا يُنقصه)"},{"id":"b","text":"pH يبقى ثابتًا عند التخفيف"},{"id":"c","text":"لا خطأ"},{"id":"d","text":"pH يصبح سالبًا"}]'::jsonb, 'a', 'إضافة الماء (تخفيف) تُقلّل تركيز الحمض فيرتفع pH مقتربًا من 7 (يصبح أقلّ حمضيّة)، لا ينقص. (تمرين «صيد الخطأ».) الخطأ الشائع: الخلط بين زيادة الحجم وزيادة الحمضيّة — التخفيف يُضعف الحمضيّة دائمًا.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('e02b8499-b377-5890-a130-980e1459cf63', 'fd002b29-306a-58a8-a501-5505114cf8fe', 'محلول حمضيّ pH = 5، خُفِّف تخفيفًا شديدًا جدًّا (بعامل 10000). ما قيمة pH؟', '[{"id":"a","text":"9"},{"id":"b","text":"1"},{"id":"c","text":"قريب من 7 دون تجاوزه (يبقى < 7)"},{"id":"d","text":"5"}]'::jsonb, 'c', 'تخفيف حمض يرفع pH نحو 7، لكنّه لا يبلغ 7 ولا يتجاوزه أبدًا: محلول حمضيّ يبقى حمضيًّا (pH < 7) مهما خُفِّف — يقترب من الحياد فقط. الحساب الساذج 5 + 4 = 9 خاطئ لأنّه يجعل الحمض قاعديًّا، وهو مستحيل بالتخفيف بالماء. ✓ الخطأ الشائع: إضافة عدد مرّات التخفيف مباشرةً إلى pH دون حدّ الحياد 7.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('5aef40da-096c-5da0-a024-1455a2662ba2', 'fd002b29-306a-58a8-a501-5505114cf8fe', 'محلول قاعديّ pH = 11، خُفِّف بالماء 10 مرّات. ما قيمة pH التقريبية؟', '[{"id":"a","text":"10"},{"id":"b","text":"12"},{"id":"c","text":"11"},{"id":"d","text":"8"}]'::jsonb, 'a', 'تخفيف محلول قاعديّ بعامل 10 يُنقص pH بمقدار وحدة نحو 7 (يصبح أقلّ قاعديّة): 11 − 1 = 10. ✓ الخطأ الشائع: ظنّ أنّ التخفيف يرفع pH القاعدة (12) — التخفيف يُقرّب من 7 من الأعلى للقاعدة ومن الأسفل للحمض.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('b40024e3-c8a5-579c-89c9-aaf7d094d74b', 'fd002b29-306a-58a8-a501-5505114cf8fe', 'محلول حمضيّ pH = 3، خُفِّف 10 مرّات ثمّ خُفِّف الناتج مرّة أخرى 10 مرّات. ما قيمة pH النهائية؟', '[{"id":"a","text":"4"},{"id":"b","text":"1"},{"id":"c","text":"3"},{"id":"d","text":"5"}]'::jsonb, 'd', 'كلّ تخفيف بعامل 10 يرفع pH الحمض بوحدة: 3 → 4 (التخفيف الأوّل) → 5 (التخفيف الثاني). القيمة 5 لا تزال < 7 فالمحلول حمضيّ أضعف. ✓ الخطأ الشائع: رفع pH بوحدة واحدة فقط (4) رغم تخفيفَين؛ أو خفض pH.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('2b8d4e5b-6b26-5283-9b0a-0ec52b4bae55', 'fd002b29-306a-58a8-a501-5505114cf8fe', 'محلولان X وY: عند إضافة أزرق البروموتيمول (BBT) إلى X اصفرّ المحلول. أمّا Y فقيس pH له 10. أيّ محلول حمضيّ، وما قيمة pH ممكنة لـ X؟', '[{"id":"a","text":"X حمضيّ (pH ≈ 3)، Y قاعديّ"},{"id":"b","text":"X قاعديّ، Y حمضيّ"},{"id":"c","text":"كلاهما حمضيّ"},{"id":"d","text":"X حمضيّ (pH = 8)"}]'::jsonb, 'a', 'أزرق البروموتيمول يصفرّ في الوسط الحمضيّ (pH < 6)، فـ X حمضيّ وقيمة pH ممكنة له أقلّ من 7 مثل 3. وY له pH = 10 > 7 فهو قاعديّ. ✓ الخطأ الشائع: نسبة اللون الأصفر لـ BBT إلى الوسط القاعديّ (الأزرق هو القاعديّ)؛ أو اقتراح pH = 8 لمحلول حمضيّ (مستحيل، > 7).', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

