INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('03d3ffec-8982-54e8-af46-bdc34a74db49', '9795d4ab-4ba5-58f5-bbb7-a2d8a35ab255', 'أيّ ممّا يلي يُعرَّف بأنّه أيون موجب (كاتيون)؟', '[{"id":"a","text":"Cl⁻"},{"id":"b","text":"Na⁺"},{"id":"c","text":"OH⁻"},{"id":"d","text":"SO₄²⁻"}]'::jsonb, 'b', 'Na⁺ هو أيون الصوديوم ويحمل شحنة موجبة (+1)، لذا هو كاتيون. أمّا Cl⁻ و OH⁻ و SO₄²⁻ فكلّها أنيونات (شحنات سالبة).', 1)
ON CONFLICT (id) DO UPDATE SET
