  ('7d98ea97-fb08-5cf9-874c-b1c7d35858a7', '1ef832e7-2310-5ebc-9ddd-7d3d868d77cb', 'svt', '⚔️ زعيم الفصل: معركة الشوارد الكهربائية', 3, 120, 30, 'boss', 'admin', 2)
