  reward_coins = EXCLUDED.reward_coins,
  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('4bdadd7a-88a2-5e0c-883c-fa2ad4fd6822', '0521d418-e9d4-5282-a308-5f99ca91a898', 'حُلَّ 11.7 g من كلوريد الصوديوم NaCl (الكتلة المولية M = 58.5 g/mol) في الماء للحصول على محلول حجمه 500 mL. ثمّ أُخذ 100 mL من هذا المحلول وأُضيف إليه 400 mL من الماء المقطّر. ما تركيز المحلول النهائي بالغرام في اللتر (g/L)؟', '[{"id":"a","text":"4.68 g/L"},{"id":"b","text":"23.4 g/L"},{"id":"c","text":"2.34 g/L"},{"id":"d","text":"11.7 g/L"}]'::jsonb, 'a', 'الخطوة 1 — تركيز المحلول الأصلي: C₁ = m/V = 11.7 g ÷ 0.5 L = 23.4 g/L. الخطوة 2 — قانون التخفيف: C₁ × V₁ = C₂ × V₂. الحجم المأخوذ V₁ = 100 mL، والحجم النهائي V₂ = 100 + 400 = 500 mL. إذن C₂ = 23.4 × 100/500 = 23.4 × 0.2 = 4.68 g/L. الخيار B هو تركيز المحلول الأوّلي (خطأ شائع بنسيان خطوة التخفيف). الخيار C يُعطي نصف القيمة الصحيحة (خطأ في عامل التخفيف). الخيار D هو كتلة NaCl الأصلية بالغرام لا التركيز.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('3a8d9fcf-667e-5cdd-afb3-39bcc0461bf2', '0521d418-e9d4-5282-a308-5f99ca91a898', 'محلول شاردي يحتوي أيونَين موجبَين: 3 mol من Na⁺ و2 mol من Ca²⁺. لكي يكون المحلول متعادلًا كهربائيًّا، كم مولًا من أيون الكلوريد Cl⁻ يجب أن يحتوي المحلول؟', '[{"id":"a","text":"5 mol"},{"id":"b","text":"7 mol"},{"id":"c","text":"6 mol"},{"id":"d","text":"3 mol"}]'::jsonb, 'b', 'شرط التعادل الكهربائي: مجموع الشحنات الموجبة = مجموع الشحنات السالبة. الشحنات الموجبة = (3 mol × +1) + (2 mol × +2) = 3 + 4 = 7 وحدة موجبة. إذن يجب أن تكون الشحنات السالبة = 7 وحدة سالبة. بما أنّ كلّ Cl⁻ يحمل شحنة −1، يلزم 7 mol من Cl⁻. الخيار A (5 mol) هو مجموع عدد مولات الأيونات الموجبة فقط دون حساب الشحنة المضاعفة لـ Ca²⁺ (خطأ شائع). الخيار C يُخطئ في حساب شحنة Ca²⁺. الخيار D يأخذ فقط Na⁺.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('bab191f2-791e-53ba-b839-6ea99c135c53', '0521d418-e9d4-5282-a308-5f99ca91a898', 'عند إضافة بضع قطرات من محلول هيدروكسيد الصوديوم NaOH إلى محلول مجهول، يتشكّل راسب أزرق. ما الأيون الموجب الذي يتميَّز بهذه الطريقة؟ (تلميح: Cu(OH)₂ رسوب أزرق، Fe(OH)₃ رسوب بنّي-أحمر، Zn(OH)₂ رسوب أبيض)', '[{"id":"a","text":"Zn²⁺"},{"id":"b","text":"Fe³⁺"},{"id":"c","text":"Na⁺"},{"id":"d","text":"Cu²⁺"}]'::jsonb, 'd', 'عند إضافة NaOH إلى المحلول يتفاعل أيون الهيدروكسيد OH⁻ مع الكاتيونات المعدنية لتكوين هيدروكسيدات راسبة. الرسوب الأزرق خاصّيته أيون النحاس الثنائي Cu²⁺ وفق التفاعل: Cu²⁺ + 2 OH⁻ → Cu(OH)₂↓ (أزرق). أمّا Zn²⁺ فيعطي رسوبًا أبيض Zn(OH)₂، وFe³⁺ يعطي رسوبًا بنّيًّا-أحمر Fe(OH)₃. أيون Na⁺ لا يكوّن راسبًا مع NaOH لأنّ NaOH نفسه ذائب تمامًا.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('9c160614-5424-53cd-b74d-7fcb08bc01ee', '0521d418-e9d4-5282-a308-5f99ca91a898', 'عند إضافة 1 L من الماء المقطّر إلى 1 L من محلول NaCl تركيزه C₁ = 20 g/L، ثمّ أُخذت من المحلول الناتج عيّنة حجمها 200 mL وخُفِّفت بإضافة الماء حتّى بلغ حجمها الإجمالي 1 L. ما تركيز المحلول في المرحلة الأخيرة (g/L)؟', '[{"id":"a","text":"10 g/L"},{"id":"b","text":"2 g/L"},{"id":"c","text":"4 g/L"},{"id":"d","text":"0.4 g/L"}]'::jsonb, 'b', 'التخفيف الأوّل: C₁ × V₁ = C₂ × V₂ ← 20 × 1 = C₂ × 2 → C₂ = 10 g/L. التخفيف الثاني: C₂ × V = C₃ × V'' ← 10 × 0.2 = C₃ × 1 → C₃ = 2 g/L. الخيار A (10 g/L) هو نتيجة التخفيف الأوّل فقط (توقّف عند منتصف الطريق). الخيار C (4 g/L) خطأ في حساب أحد عاملَي التخفيف. الخيار D (0.4 g/L) يُخطئ في تحويل الوحدات أو ترتيب العمليات.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('c4d933cf-0723-5b04-9512-73b2a26bbfd3', '0521d418-e9d4-5282-a308-5f99ca91a898', 'أُذيب حمض كلور الهيدروجين HCl في الماء فانحلّ تمامًا إلى H⁺ و Cl⁻. ثمّ أُضيف إلى المحلول الناتج كميّةٌ مكافئة (من حيث عدد المولات) من هيدروكسيد الصوديوم NaOH ليتشرّد تمامًا إلى Na⁺ و OH⁻. بعد التفاعل التام بين H⁺ و OH⁻ (تفاعل التعادل: H⁺ + OH⁻ → H₂O)، أيّ الأيونات يبقى في المحلول؟', '[{"id":"a","text":"H⁺ و OH⁻ فقط"},{"id":"b","text":"لا توجد أيونات — المحلول أصبح غير شاردي"},{"id":"c","text":"Na⁺ و Cl⁻ فقط"},{"id":"d","text":"Na⁺ و OH⁻ فقط"}]'::jsonb, 'c', 'عند التعادل بين HCl وNaOH بكميّات مكافئة: H⁺ + OH⁻ → H₂O (يتّحدان ويختفيان). تبقى في المحلول الأيونات المتفرّجة (الطيفية) التي لم تشارك في التفاعل وهي Na⁺ (من NaOH) و Cl⁻ (من HCl). المحلول الناتج شاردي — يحتوي Na⁺ و Cl⁻ — وهو محلول ملح الطعام NaCl. لذا الخيار B خاطئ تمامًا: التعادل لا يُزيل الأيونات الطيفية. الخيار A خاطئ لأنّ H⁺ و OH⁻ تفاعلا وتحوّلا إلى ماء. الخيار D خاطئ لأنّ OH⁻ أُنفق في التفاعل.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('aa3037c2-dc2e-5317-9d51-fdf5bfbe32e1', '0521d418-e9d4-5282-a308-5f99ca91a898', 'محلولان: المحلول A حجمه 250 mL ويحتوي 7.3 g من HCl (M = 36.5 g/mol)، والمحلول B حجمه 500 mL ويحتوي 14.6 g من HCl. مقارنةً بالناقلية الكهربائية: أيّ العبارات صحيحة؟', '[{"id":"a","text":"A أقلّ ناقليةً من B لأنّ كتلة HCl في A أقلّ"},{"id":"b","text":"B أكثر ناقليةً من A لأنّ حجمه أكبر"},{"id":"c","text":"A و B لهما ناقلية متساوية لأنّ تركيزيهما متساويان"},{"id":"d","text":"A أكثر ناقليةً من B لأنّ تركيزه أعلى"}]'::jsonb, 'c', 'الحساب: تركيز A: C_A = 7.3 g ÷ 0.250 L = 29.2 g/L. تركيز B: C_B = 14.6 g ÷ 0.500 L = 29.2 g/L. التركيزان متساويان تمامًا! بما أنّ الناقلية الكهربائية تعتمد على تركيز الشوارد في وحدة الحجم (لا على الكمية الكلية في المحلول)، فإنّ A و B يتساويان في الناقلية رغم اختلاف حجمَيهما وكتلتَي HCl المذابَين فيهما. الخيار A يُخطئ بمقارنة الكتل بدل التركيزات. الخيار B يُخطئ بمقارنة الأحجام بدل التركيزات. الخيار D صحيح المبدأ لكن خاطئ التطبيق لأنّ التركيزَين متساويان.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('ba7718f3-4caf-57bf-81b4-59c3644ce233', '1ef832e7-2310-5ebc-9ddd-7d3d868d77cb', 'svt', '🎯 تدرّب على المحاليل الشاردية وناقلية الكهرباء', 3, 120, 30, 'boss', 'admin', 5)
ON CONFLICT (id) DO UPDATE SET
  chapter_id = EXCLUDED.chapter_id,
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  difficulty = EXCLUDED.difficulty,
  xp_reward = EXCLUDED.xp_reward,
  reward_coins = EXCLUDED.reward_coins,
  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('85f46ae6-9044-553b-8363-0fe65dc1d33b', 'ba7718f3-4caf-57bf-81b4-59c3644ce233', 'الشاردة (الأيون) هي:', '[{"id":"a","text":"ذرّة أو مجموعة ذرّات اكتسبت أو فقدت إلكترونات فأصبحت مشحونة"},{"id":"b","text":"ذرّة متعادلة كهربائيًّا"},{"id":"c","text":"جزيء لا يحمل أيّ شحنة"},{"id":"d","text":"نواة بدون إلكترونات"}]'::jsonb, 'a', 'الشاردة ذرّة أو مجموعة ذرّات فقدت إلكترونات (فأصبحت موجبة = كاتيون) أو اكتسبت إلكترونات (فأصبحت سالبة = أنيون). أمّا الذرّة المتعادلة فعدد إلكتروناتها يساوي عدد شحنات نواتها.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('3ee0c644-5450-5bf8-abe5-7f7ca485336e', 'ba7718f3-4caf-57bf-81b4-59c3644ce233', 'الشاردة الموجبة تُسمّى كاتيونًا، فأيّ مما يلي كاتيون؟', '[{"id":"a","text":"شاردة الكلور Cl⁻"},{"id":"b","text":"شاردة الصوديوم Na⁺"},{"id":"c","text":"شاردة الكبريتات SO₄²⁻"},{"id":"d","text":"شاردة الهيدروكسيد OH⁻"}]'::jsonb, 'b', 'الكاتيون شاردة موجبة (إشارة + أعلى الرمز). Na⁺ كاتيون لأنّه موجب. أمّا Cl⁻ وSO₄²⁻ وOH⁻ فأنيونات (سالبة).', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('f3cd7ae0-2701-5931-91b4-035081d52e3b', 'ba7718f3-4caf-57bf-81b4-59c3644ce233', 'لماذا يكون محلول ملح الطعام (كلور الصوديوم) في الماء ناقلًا للتيار الكهربائي؟', '[{"id":"a","text":"لأنّه يحتوي على جزيئات ماء فقط"},{"id":"b","text":"لأنّه يحتوي على شوارد حرّة الحركة (Na⁺ و Cl⁻)"},{"id":"c","text":"لأنّ الماء وحده ناقل ممتاز"},{"id":"d","text":"لأنّ السكّر موجود فيه"}]'::jsonb, 'b', 'ناقلية المحلول تعود إلى وجود شوارد حرّة الحركة. ينحلّ كلور الصوديوم إلى Na⁺ وCl⁻ تتحرّك نحو القطبين فتنقل التيار. الماء النقي وحده ناقل ضعيف جدًّا، ومحلول السكّر غير ناقل لأنّه لا يعطي شوارد.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('05825851-7a5b-5761-a954-efe703a01cfa', 'ba7718f3-4caf-57bf-81b4-59c3644ce233', 'أيّ المحاليل التالية غير ناقل للتيار الكهربائي؟', '[{"id":"a","text":"محلول كلور الصوديوم"},{"id":"b","text":"محلول حمض الكلور"},{"id":"c","text":"محلول السكّر"},{"id":"d","text":"محلول هيدروكسيد الصوديوم"}]'::jsonb, 'c', 'محلول السكّر غير ناقل لأنّ السكّر ينحلّ على شكل جزيئات متعادلة لا تعطي شوارد. أمّا الأملاح والأحماض والقواعد فتعطي شوارد حرّة فتجعل المحلول ناقلًا (محاليل شاردية).', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('2c551ce0-10b8-5072-9761-8d4fba83b0e4', 'ba7718f3-4caf-57bf-81b4-59c3644ce233', 'عند زيادة تركيز محلول شاردي (إذابة كمّية أكبر من الملح في نفس حجم الماء)، فإنّ ناقليته الكهربائية:', '[{"id":"a","text":"تنقص"},{"id":"b","text":"تزداد لزيادة عدد الشوارد الناقلة"},{"id":"c","text":"تبقى ثابتة"},{"id":"d","text":"تنعدم"}]'::jsonb, 'b', 'كلّما زاد التركيز زاد عدد الشوارد الحرّة في وحدة الحجم، فتزداد ناقلية المحلول (إلى حدّ التشبّع). فالناقلية تتناسب طرديًّا مع تركيز الشوارد.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('2231fe26-ab77-5ff2-80a6-01402facf2da', 'ba7718f3-4caf-57bf-81b4-59c3644ce233', 'في تجربة ناقلية تستعمل مصباحًا في الدارة: عند غمر القطبين في محلول شاردي مركّز يضيء المصباح بشدّة، وفي محلول مخفّف يضيء بخفوت. ماذا نستنتج؟', '[{"id":"a","text":"شدّة الإضاءة لا علاقة لها بالتركيز"},{"id":"b","text":"شدّة الإضاءة تدلّ على شدّة التيار، وهي تزداد بزيادة الناقلية (التركيز)"},{"id":"c","text":"المحلول المخفّف أكثر ناقلية"},{"id":"d","text":"المصباح يضيء بسبب الماء وحده"}]'::jsonb, 'b', 'إضاءة المصباح مؤشّر على شدّة التيار المار، وهي تكبر كلّما زادت ناقلية المحلول. المحلول المركّز (شوارد أكثر) أكثر ناقلية فيمرّ تيار أكبر ويضيء المصباح بشدّة، عكس المحلول المخفّف.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('934d376f-8b82-5545-83ff-56519517faa9', '1ef832e7-2310-5ebc-9ddd-7d3d868d77cb', 'svt', '👑 تحدّي المناظرة ⭐⭐⭐⭐: المحاليل الشاردية — تركيز وتعادل وناقلية', 4, 300, 60, 'challenge', 'admin', 6)
ON CONFLICT (id) DO UPDATE SET
  chapter_id = EXCLUDED.chapter_id,
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  difficulty = EXCLUDED.difficulty,
  xp_reward = EXCLUDED.xp_reward,
  reward_coins = EXCLUDED.reward_coins,
  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('d2e62b06-1ccf-5240-9d6f-4ddd4d818551', '934d376f-8b82-5545-83ff-56519517faa9', 'ثلاثة محاليل: ماء + ملح الطعام (NaCl)، وماء + سكّر، وماء مقطّر. أيّها ناقلٌ للتيّار الكهربائيّ؟', '[{"id":"a","text":"ماء + ملح الطعام فقط"},{"id":"b","text":"ماء + سكّر فقط"},{"id":"c","text":"الثلاثة كلّها"},{"id":"d","text":"لا شيء منها"}]'::jsonb, 'a', 'ينقل المحلولُ التيّار إذا احتوى على شوارد (أيونات) حرّة الحركة. ملح الطعام يذوب مُعطيًا شوارد Na⁺ و Cl⁻ فيصير المحلول ناقلًا؛ أمّا السكّر فيذوب كجزيئات متعادلة (لا شوارد) والماء المقطّر خالٍ عمليًّا من الشوارد، فكلاهما غير ناقل. ✓ الخطأ الشائع: اعتبار محلول السكّر (محلول جزيئيّ) ناقلًا — الذوبان وحده لا يكفي، لا بدّ من تكوّن شوارد.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('5f2d9998-14fc-5e40-a276-7406bcf5c89e', '934d376f-8b82-5545-83ff-56519517faa9', 'قال تلميذ: «كلّما خُفِّف محلول شاردي بإضافة الماء، زادت ناقليّته للتيّار الكهربائيّ». ما الخطأ؟', '[{"id":"a","text":"التخفيف يُنقص تركيز الشوارد، فتقلّ الناقليّة لا تزيد"},{"id":"b","text":"لا خطأ، الناقليّة تزيد بالتخفيف"},{"id":"c","text":"الناقليّة لا تتعلّق بتركيز الشوارد"},{"id":"d","text":"التخفيف يحوّل المحلول إلى جزيئيّ"}]'::jsonb, 'a', 'ناقليّة المحلول الشاردي تزداد بازدياد تركيز الشوارد (عند ثبات النوع والدرجة). التخفيف بإضافة الماء يُنقص عدد الشوارد في وحدة الحجم، فتقلّ الناقليّة. (تمرين «صيد الخطأ».) الخطأ الشائع: ربط زيادة كمّية السائل بزيادة الناقلية — العكس هو الصحيح.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('8bc84b28-3731-5d03-936d-dc885dad8c2f', '934d376f-8b82-5545-83ff-56519517faa9', 'محلول ملحيّ حجمه 200 mL يحتوي على 8 g من الملح المذاب. ما تركيزه الكتليّ C؟ ثمّ أُضيف ماء حتى صار الحجم 500 mL — ما التركيز الكتليّ الجديد؟', '[{"id":"a","text":"40 g/L ثمّ 16 g/L"},{"id":"b","text":"40 g/L ثمّ 40 g/L"},{"id":"c","text":"0,04 g/L ثمّ 0,016 g/L"},{"id":"d","text":"16 g/L ثمّ 40 g/L"}]'::jsonb, 'a', 'التركيز الكتليّ C = كتلة المذاب / حجم المحلول (بالـ L). أوّلًا: 200 mL = 0,2 L، فـ C = 8/0,2 = 40 g/L. عند التخفيف تبقى كتلة المذاب 8 g بينما يصير الحجم 0,5 L، فـ C′ = 8/0,5 = 16 g/L (أصغر — التخفيف يُنقص التركيز). ✓ الخطأ الشائع: عدم تحويل mL إلى L (8/200 = 0,04 g/L)؛ أو ظنّ التركيز لا يتغيّر بالتخفيف (40 g/L)؛ أو قلب القيمتَين.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('5783a465-1571-52e8-ab0c-fbde43693313', '934d376f-8b82-5545-83ff-56519517faa9', 'محلول شاردي يحتوي على شوارد الألومنيوم Al³⁺ وشوارد الكبريتات SO₄²⁻ فقط. إذا احتوى على 6 mol من Al³⁺، فكم مولًا من SO₄²⁻ يلزم لكي يكون المحلول متعادلًا كهربائيًّا؟', '[{"id":"a","text":"9 mol"},{"id":"b","text":"6 mol"},{"id":"c","text":"18 mol"},{"id":"d","text":"4 mol"}]'::jsonb, 'a', 'التعادل الكهربائيّ: مجموع الشحنات الموجبة = مجموع الشحنات السالبة (بعدد الشحنات لا بعدد المولات). الموجبة = 6 mol × 3 = 18. لتعادلها بشوارد شحنة كلٍّ منها 2: عدد المولات = 18 / 2 = 9 mol. ✓ الخطأ الشائع: مساواة عدد المولات مباشرةً (6 mol) وإهمال قيمة الشحنة؛ أو نسيان القسمة على 2 (18 mol).', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('484640a7-4876-5053-8067-04e6b88a7b1c', '934d376f-8b82-5545-83ff-56519517faa9', 'لكشف شاردة موجودة في محلول مجهول، أُضيف إليه محلول نترات الفضّة AgNO₃ فتشكّل راسبٌ أبيض (كلور الفضّة AgCl). ما الشاردة السالبة الموجودة في المحلول؟', '[{"id":"a","text":"شاردة الكلور Cl⁻"},{"id":"b","text":"شاردة الكبريتات SO₄²⁻"},{"id":"c","text":"شاردة النحاس Cu²⁺"},{"id":"d","text":"شاردة الهيدروكسيد OH⁻"}]'::jsonb, 'a', 'الراسب الأبيض مع نترات الفضّة AgNO₃ هو الاختبار المميّز لشاردة الكلور Cl⁻ (يتكوّن AgCl الأبيض). ✓ الخطأ الشائع: نسبة الراسب إلى الكبريتات SO₄²⁻ (اختبارها بشاردة الباريوم Ba²⁺ لا الفضّة)؛ أو اقتراح شاردةٍ موجبة مثل Cu²⁺ (وهي كاتيون، والراسب هنا يكشف أنيونًا).', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('b7aa2171-2694-529d-b5fb-963f72f9f35b', '934d376f-8b82-5545-83ff-56519517faa9', 'أُذيب 4 g من هيدروكسيد الصوديوم NaOH (الكتلة المولية M = 40 g/mol) في ماء للحصول على 500 mL من المحلول. ما التركيز المولي Cm للمحلول؟', '[{"id":"a","text":"0,2 mol/L"},{"id":"b","text":"0,1 mol/L"},{"id":"c","text":"8 mol/L"},{"id":"d","text":"0,008 mol/L"}]'::jsonb, 'a', 'أوّلًا عدد المولات: n = m/M = 4/40 = 0,1 mol. ثمّ التركيز المولي: Cm = n/V مع V = 500 mL = 0,5 L، فـ Cm = 0,1/0,5 = 0,2 mol/L. ✓ الخطأ الشائع: التوقّف عند n = 0,1 وإعطائه تركيزًا (نسيان القسمة على الحجم)؛ أو القسمة على الكتلة المولية دون حسابها (4/0,5 = 8)؛ أو عدم تحويل mL إلى L (0,1/500 = 0,0002 أو 0,008).', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

