  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('4c6d3e90-677a-5b28-8ff3-05873bda0227', '312fd190-acd6-519d-b510-a59663bf790c', 'مقاومتان على التوازي: R₁ = 4 Ω و R₂ = 4 Ω. ما المقاومة الإجمالية؟', '[{"id":"a","text":"8 Ω"},{"id":"b","text":"4 Ω"},{"id":"c","text":"1 Ω"},{"id":"d","text":"2 Ω"}]'::jsonb, 'd', 'في التوازي: 1/R_total = 1/4 + 1/4 = 2/4 = 1/2، إذن R_total = 2 Ω. المقاومة الإجمالية في التوازي دائمًا أصغر من أصغر مقاومة منفردة.', 5)
