  ('20104077-d1f6-503d-84fc-5b7efb1e330d', 'cb55bcb6-c41c-5c05-b94a-fad88e81e703', 'svt', '🎯 تدرّب على التيار المستمر وقانون أوم', 3, 120, 30, 'boss', 'admin', 5)
