INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('26cffb7f-9723-5a9d-8dbf-0e2773c23efe', '9b218a44-a954-511d-9af1-a3bf955cf49a', 'ثلاث مقاومات على التسلسل R₁ = 10 Ω و R₂ = 20 Ω و R₃ = 30 Ω، موصولة بمصدر توتره U = 12 V. ما شدّة التيار المارّ في الدائرة؟', '[{"id":"a","text":"0,4 A"},{"id":"b","text":"0,2 A"},{"id":"c","text":"1,2 A"},{"id":"d","text":"2 A"}]'::jsonb, 'b', 'على التسلسل تُجمع المقاومات: R = R₁ + R₂ + R₃ = 10 + 20 + 30 = 60 Ω. ثمّ بقانون أوم: I = U/R = 12/60 = 0,2 A. ✓ (الوحدة: V/Ω = A). الخطأ الشائع: تطبيق التوتر الكلّي على مقاومة واحدة (12/10 = 1,2 A)؛ أو قلب الصيغة.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('41f18b98-e549-51fa-92dc-076e0e17043c', '9b218a44-a954-511d-9af1-a3bf955cf49a', 'لحساب مقاومة عند U = 12 V و I = 3 A، كتب تلميذ: «R = U × I = 12 × 3 = 36 Ω». ما الخطأ؟', '[{"id":"a","text":"الصواب R = U/I = 12/3 = 4 Ω"},{"id":"b","text":"الحساب صحيح لكنّ الوحدة خاطئة"},{"id":"c","text":"لا خطأ"},{"id":"d","text":"الصواب R = I/U = 0,25 Ω"}]'::jsonb, 'a', 'قانون أوم U = R × I، ومنه R = U/I = 12/3 = 4 Ω (لا U × I). (تمرين «صيد الخطأ».) الخطأ الشائع: ضرب U في I بدل قسمتهما؛ التحقّق بالوحدة: V/A = Ω.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('2f287380-6e86-5e3d-8ffb-4b758e37acae', '9b218a44-a954-511d-9af1-a3bf955cf49a', 'مقاومتان على التوازي R₁ = 6 Ω و R₂ = 3 Ω. ما المقاومة المكافئة؟', '[{"id":"a","text":"9 Ω"},{"id":"b","text":"4,5 Ω"},{"id":"c","text":"2 Ω"},{"id":"d","text":"18 Ω"}]'::jsonb, 'c', 'على التوازي: 1/R = 1/R₁ + 1/R₂ = 1/6 + 1/3 = 1/6 + 2/6 = 3/6 = 1/2، إذن R = 2 Ω. (أو R = (R₁ × R₂)/(R₁ + R₂) = 18/9 = 2 Ω). ✓ ملاحظة: المقاومة المكافئة على التوازي أصغر من أصغر مقاومة. الخطأ الشائع: جمع المقاومات كما في التسلسل (9 Ω)؛ أو أخذ المعدّل (4,5 Ω).', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('b811f72d-42d7-556e-87f0-a9ac9449e7fc', '9b218a44-a954-511d-9af1-a3bf955cf49a', 'R₁ = 4 Ω على التسلسل مع مجموعة توازٍ (R₂ = 10 Ω و R₃ = 15 Ω)، والتوتر الكلّي U = 20 V. ما شدّة التيار المارّ في R₃؟', '[{"id":"a","text":"2 A"},{"id":"b","text":"1,2 A"},{"id":"c","text":"1,33 A"},{"id":"d","text":"0,8 A"}]'::jsonb, 'd', 'الخطوة 1 — مقاومة التوازي: R₂₃ = (10 × 15)/(10 + 15) = 150/25 = 6 Ω. الخطوة 2 — المقاومة الكلّية: R = R₁ + R₂₃ = 4 + 6 = 10 Ω. الخطوة 3 — التيار الكلّي: I = U/R = 20/10 = 2 A. الخطوة 4 — التوتر عبر مجموعة التوازي: U₂₃ = I × R₂₃ = 2 × 6 = 12 V. الخطوة 5 — التيار في R₃: I₃ = U₂₃/R₃ = 12/15 = 0,8 A. ✓ (تحقّق: I₂ = 12/10 = 1,2 A، وI₂ + I₃ = 1,2 + 0,8 = 2 A = التيار الكلّي). الخطأ الشائع: إعطاء التيار الكلّي 2 A أو تيار الفرع الآخر 1,2 A بدل تيار R₃.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('0a237539-1951-5306-95e9-38f9016082f1', '9b218a44-a954-511d-9af1-a3bf955cf49a', 'ثنائيّ قطب يُطبَّق بين طرفَيه توتر 4,5 V فيمرّ فيه تيار شدّته I = 150 mA. ما مقاومته؟', '[{"id":"a","text":"0,03 Ω"},{"id":"b","text":"30 Ω"},{"id":"c","text":"675 Ω"},{"id":"d","text":"0,675 Ω"}]'::jsonb, 'b', 'نحوّل أوّلًا الوحدة: 150 mA = 0,150 A. ثمّ بقانون أوم: R = U/I = 4,5/0,150 = 30 Ω. ✓ الخطأ الشائع: عدم تحويل mA إلى A (4,5/150 = 0,03 Ω)؛ أو ضرب بدل القسمة (4,5 × 150 = 675).', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('1dac57da-3591-5434-819d-416864b4df8b', '9b218a44-a954-511d-9af1-a3bf955cf49a', 'قِيست خصائص ثنائيّ قطب: عند U = 2 V كان I = 0,5 A ؛ عند U = 4 V كان I = 1 A ؛ عند U = 6 V كان I = 1,5 A. هل هو ثنائيّ قطب أوميّ، وما مقاومته؟', '[{"id":"a","text":"أوميّ، R = 4 Ω"},{"id":"b","text":"غير أوميّ، R متغيّرة"},{"id":"c","text":"أوميّ، R = 0,25 Ω"},{"id":"d","text":"أوميّ، R = 8 Ω"}]'::jsonb, 'a', 'نحسب النسبة U/I عند كلّ قياس: 2/0,5 = 4 ؛ 4/1 = 4 ؛ 6/1,5 = 4. النسبة ثابتة، فالثنائيّ أوميّ ومقاومته R = U/I = 4 Ω (التوتر متناسب مع الشدّة). ✓ الخطأ الشائع: حساب I/U = 0,25 بدل U/I؛ أو الحكم بأنّه غير أوميّ رغم ثبات النسبة.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('e4664661-53c0-52a7-b2b1-1195c085ebcb', 'b2e35220-fa37-5041-9ccc-4f6185e73e37', 'svt', 'اختبار مراجعة شاملة: ضوء + كهرباء + كيمياء', 1, 20, 5, 'quiz', 'admin', 0)
ON CONFLICT (id) DO UPDATE SET
  chapter_id = EXCLUDED.chapter_id,
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  difficulty = EXCLUDED.difficulty,
  xp_reward = EXCLUDED.xp_reward,
  reward_coins = EXCLUDED.reward_coins,
  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('11b0e0e2-c4f7-526a-ad0a-d4ca7e65ceb2', 'e4664661-53c0-52a7-b2b1-1195c085ebcb', 'في دارة كهربائية تسلسلية، يمرّ تيار I = 0,3 A في مقاومة R = 40 Ω. ما التوتر U على طرفَيها؟', '[{"id":"a","text":"133,3 V"},{"id":"b","text":"12 V"},{"id":"c","text":"40,3 V"},{"id":"d","text":"1,2 V"}]'::jsonb, 'b', 'نطبّق قانون أوم بالشكل المناسب للمجهول U: U = R × I = 40 × 0,3 = 12 V. الخيار 133,3 V خطأ ناتج عن قلب القانون (40 ÷ 0,3)، وهو خطأ شائع.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('aa1d367b-3e60-5b20-8904-2c469bf25380', 'e4664661-53c0-52a7-b2b1-1195c085ebcb', 'المعادلة التالية تمثّل احتراق الكربون: C + O₂ → CO₂. هل هي موزونة؟', '[{"id":"a","text":"نعم، عدد ذرّات كلّ عنصر متساوٍ في الطرفين"},{"id":"b","text":"لا، يجب أن تصبح 2C + O₂ → CO₂"},{"id":"c","text":"لا، يجب أن تصبح C + 2O₂ → CO₂"},{"id":"d","text":"لا يمكن معرفة ذلك دون معرفة الكتل"}]'::jsonb, 'a', 'نحصي ذرّات كلّ عنصر: الكربون 1 يسارًا (C) و1 يمينًا (CO₂) ✓؛ الأكسجين 2 يسارًا (O₂) و2 يمينًا (CO₂) ✓. بما أنّ عدد ذرّات كلّ عنصر متساوٍ في الطرفين فالمعادلة موزونة فعلًا.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('3a0a3dca-8a63-5182-bac1-d2e8aaa1ffcf', 'e4664661-53c0-52a7-b2b1-1195c085ebcb', 'محلول قيمة pH فيه تساوي 3. كيف نصنّفه؟', '[{"id":"a","text":"قاعدي"},{"id":"b","text":"محايد"},{"id":"c","text":"حمضي"},{"id":"d","text":"نقيّ خالٍ من الأيونات"}]'::jsonb, 'c', 'سلّم pH يمتدّ من 0 إلى 14: pH < 7 محلول حمضي، pH = 7 محايد، pH > 7 قاعدي. وبما أنّ 3 < 7 فالمحلول حمضي.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('1c2aca25-b0a3-52b5-8bd8-0bfac8ec031e', 'e4664661-53c0-52a7-b2b1-1195c085ebcb', 'عدسة مجمّعة بُعدها البؤري f = 50 cm. ما قدرتها C بالديوبتر (δ)؟', '[{"id":"a","text":"C = 50 δ"},{"id":"b","text":"C = 0,02 δ"},{"id":"c","text":"C = 2 δ"},{"id":"d","text":"C = 5 δ"}]'::jsonb, 'c', 'القدرة C = 1/f بشرط أن يكون f بالمتر. نحوّل: f = 50 cm = 0,50 m. إذن C = 1 / 0,50 = 2 δ. الخطأ الشائع هو استعمال f بالسنتيمتر فيُعطي 1/50 = 0,02، لذا يجب التحويل إلى المتر أوّلًا.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('84dc8944-00fa-5e9c-b67a-fbf031429284', 'e4664661-53c0-52a7-b2b1-1195c085ebcb', 'تفاعل بين متفاعلَين كتلتاهما 5 g و 11 g أعطى ناتجًا واحدًا. ما كتلة الناتج وفق انحفاظ الكتلة؟', '[{"id":"a","text":"6 g"},{"id":"b","text":"16 g"},{"id":"c","text":"11 g"},{"id":"d","text":"55 g"}]'::jsonb, 'b', 'بمبدأ انحفاظ الكتلة: كتلة النواتج = مجموع كتل المتفاعلات = 5 + 11 = 16 g. الخيار 6 g خطأ ناتج عن طرح بدل جمع.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('d7e8f052-8a89-50a5-a990-dd2313f6736e', 'e4664661-53c0-52a7-b2b1-1195c085ebcb', 'مقاومتان R₁ = 10 Ω و R₂ = 15 Ω موصولتان على التسلسل بمصدر توتّره U = 5 V. ما شدّة التيار I في الدارة؟', '[{"id":"a","text":"0,5 A"},{"id":"b","text":"0,2 A"},{"id":"c","text":"1,25 A"},{"id":"d","text":"125 A"}]'::jsonb, 'b', 'في التسلسل: R_total = R₁ + R₂ = 10 + 15 = 25 Ω. ثمّ I = U / R_total = 5 / 25 = 0,2 A. هذا التيار نفسه يمرّ في كلّ من R₁ و R₂.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('ecc2f575-6ed9-5206-b2ec-34280a1ff6ed', 'e4664661-53c0-52a7-b2b1-1195c085ebcb', 'ما الموازنة الصحيحة لتفاعل تكوّن الماء من عنصرَيه: H₂ + O₂ → H₂O؟', '[{"id":"a","text":"H₂ + O₂ → H₂O"},{"id":"b","text":"2H₂ + O₂ → 2H₂O"},{"id":"c","text":"H₂ + O₂ → 2H₂O"},{"id":"d","text":"2H₂ + 2O₂ → H₂O"}]'::jsonb, 'b', 'نوازن بتعديل المعاملات فقط. الصيغة الأصلية غير موزونة (الأكسجين 2 يسارًا و1 يمينًا). بوضع 2H₂ + O₂ → 2H₂O: الهيدروجين يسارًا 2×2=4 ويمينًا 2×2=4 ✓؛ الأكسجين يسارًا 2 ويمينًا 2×1=2 ✓. إذن المعادلة موزونة.', 7)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('d80a90fe-0107-5376-9799-ea15ab567637', 'e4664661-53c0-52a7-b2b1-1195c085ebcb', 'وُضع جسم أمام عدسة مجمّعة على بُعد يفوق ضعف البُعد البؤري (d > 2f). ما طبيعة الصورة المتكوّنة؟', '[{"id":"a","text":"حقيقية مقلوبة مصغّرة"},{"id":"b","text":"حقيقية معتدلة مكبّرة"},{"id":"c","text":"تخيّليّة معتدلة مكبّرة"},{"id":"d","text":"لا تتكوّن أيّ صورة"}]'::jsonb, 'a', 'حين يكون الجسم بعيدًا (d > 2f) تتقاطع الأشعّة بعد العدسة فتتكوّن صورة حقيقية يمكن إسقاطها على شاشة، وتكون مقلوبة (لتقاطع الأشعّة) ومصغّرة (لأنّها أقرب إلى العدسة من الجسم). وعلى هذا المبدأ تعمل آلة التصوير.', 8)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('1e96ef97-b150-58ae-aa74-945473352b23', 'b2e35220-fa37-5041-9ccc-4f6185e73e37', 'svt', '📝 سبر نموذجي 1: وضعيّات تطبيقية (تدريب)', 2, 50, 10, 'practice', 'admin', 1)
ON CONFLICT (id) DO UPDATE SET
  chapter_id = EXCLUDED.chapter_id,
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  difficulty = EXCLUDED.difficulty,
  xp_reward = EXCLUDED.xp_reward,
  reward_coins = EXCLUDED.reward_coins,
  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('3e90f166-17c9-578e-8714-e1035c64d5a7', '1e96ef97-b150-58ae-aa74-945473352b23', 'الوضعيّة (كهرباء): دارة بسيطة فيها مصباح مقاومته R = 30 Ω وأمبيرمتر يقرأ I = 0,2 A. ما التوتر U على طرفَي المصباح؟', '[{"id":"a","text":"150 V"},{"id":"b","text":"30,2 V"},{"id":"c","text":"6 V"},{"id":"d","text":"0,006 V"}]'::jsonb, 'c', 'المطلوب U، والمعطيات R وI، فنطبّق قانون أوم بشكله المباشر: U = R × I = 30 × 0,2 = 6 V. الخيار 150 V خطأ ناتج عن قلب القانون (30 ÷ 0,2).', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('3f2421ee-d767-51bf-8746-a44d42703b67', '1e96ef97-b150-58ae-aa74-945473352b23', 'الوضعيّة (كيمياء): تجربة احتراق غاز الميثان وفق المعادلة CH₄ + 2O₂ → CO₂ + 2H₂O. كم جزيء ماء ينتج عن كلّ جزيء ميثان؟', '[{"id":"a","text":"جزيء واحد"},{"id":"b","text":"جزيئان"},{"id":"c","text":"أربعة جزيئات"},{"id":"d","text":"لا ينتج ماء"}]'::jsonb, 'b', 'المعامل أمام H₂O في المعادلة هو 2، أي أنّ كلّ جزيء ميثان (CH₄) يعطي جزيئَين من الماء (2H₂O). المعامل يقرأ مباشرةً من المعادلة الموزونة.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('993af936-bc6d-5186-8a5a-a966b4f40aac', '1e96ef97-b150-58ae-aa74-945473352b23', 'الوضعيّة (ضوء): شعاع ضوئي ينتقل من الهواء إلى الماء (الماء أكثر كثافة بصرية). كيف ينكسر الشعاع عند سطح الفصل؟', '[{"id":"a","text":"ينكسر مبتعدًا عن الناظم (i₂ > i₁)"},{"id":"b","text":"ينكسر مقتربًا من الناظم (i₂ < i₁)"},{"id":"c","text":"يواصل في خطّ مستقيم دون انكسار"},{"id":"d","text":"ينعكس كلّيًّا دون أن ينفذ"}]'::jsonb, 'b', 'عند الانتقال من وسط أقلّ كثافة بصرية (الهواء) إلى وسط أكثر كثافة (الماء) ينكسر الشعاع نحو الناظم، فتكون زاوية الانكسار i₂ أصغر من زاوية الورود i₁.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('3a6aac6d-171e-5498-80f9-8b7aa986a6ea', '1e96ef97-b150-58ae-aa74-945473352b23', 'الوضعيّة (كهرباء): مقاومتان R₁ = 20 Ω و R₂ = 30 Ω موصولتان على التسلسل. ما المقاومة الإجمالية للدارة؟', '[{"id":"a","text":"12 Ω"},{"id":"b","text":"50 Ω"},{"id":"c","text":"600 Ω"},{"id":"d","text":"10 Ω"}]'::jsonb, 'b', 'في التركيب على التسلسل تُجمع المقاومات: R_total = R₁ + R₂ = 20 + 30 = 50 Ω. الخيار 12 Ω خطأ لأنّه يطبّق قاعدة التوازي (1/R = 1/20 + 1/30) في موضع التسلسل.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('4ce33a62-ca4f-5151-af7d-c3538937cb4a', '1e96ef97-b150-58ae-aa74-945473352b23', 'الوضعيّة (كيمياء): قياس pH لثلاثة محاليل أعطى: محلول أ pH = 2، محلول ب pH = 7، محلول ج pH = 11. أيّ ترتيب صحيح؟', '[{"id":"a","text":"أ حمضي، ب محايد، ج قاعدي"},{"id":"b","text":"أ قاعدي، ب محايد، ج حمضي"},{"id":"c","text":"أ محايد، ب حمضي، ج قاعدي"},{"id":"d","text":"الثلاثة محايدة"}]'::jsonb, 'a', 'وفق سلّم pH: قيمة أقلّ من 7 حمضية، تساوي 7 محايدة، أكبر من 7 قاعدية. إذن أ (2) حمضي، ب (7) محايد، ج (11) قاعدي.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('50dcbcda-e6f6-52e7-ad54-96dd78e5a8e2', '1e96ef97-b150-58ae-aa74-945473352b23', 'الوضعيّة (ضوء): عدسة مجمّعة بُعدها البؤري f = 20 cm. ما قدرتها C بالديوبتر؟', '[{"id":"a","text":"C = 20 δ"},{"id":"b","text":"C = 0,05 δ"},{"id":"c","text":"C = 5 δ"},{"id":"d","text":"C = 2 δ"}]'::jsonb, 'c', 'القدرة C = 1/f مع f بالمتر. نحوّل: f = 20 cm = 0,20 m. إذن C = 1 / 0,20 = 5 δ. الخطأ الشائع هو نسيان تحويل cm إلى m فيُحسب 1/20 = 0,05.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('e2a437e0-aeea-5e14-ae20-8a53cb85c225', 'b2e35220-fa37-5041-9ccc-4f6185e73e37', 'svt', '⚔️ سبر نموذجي 2: تحليل وضعيّات (زعيم الفصل)', 3, 120, 30, 'boss', 'admin', 2)
ON CONFLICT (id) DO UPDATE SET
  chapter_id = EXCLUDED.chapter_id,
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  difficulty = EXCLUDED.difficulty,
  xp_reward = EXCLUDED.xp_reward,
  reward_coins = EXCLUDED.reward_coins,
  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('e2f1526e-3a54-504a-ad01-619273046472', 'e2a437e0-aeea-5e14-ae20-8a53cb85c225', 'وضعيّة (كهرباء): دارة تسلسلية بها مصدر U = 6 V ومقاومتان R₁ = 10 Ω و R₂ = 5 Ω. احسب شدّة التيار I في الدارة.', '[{"id":"a","text":"0,4 A"},{"id":"b","text":"1,2 A"},{"id":"c","text":"0,6 A"},{"id":"d","text":"2,5 A"}]'::jsonb, 'a', 'في التسلسل: R_total = R₁ + R₂ = 10 + 5 = 15 Ω. ثمّ I = U / R_total = 6 / 15 = 0,4 A. الخيار 1,2 A خطأ ناتج عن قلب القانون (15 ÷ ... ) أو استعمال مقاومة واحدة فقط.', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('9fac4f19-53d7-5c31-a08d-a74739ef5a9a', 'e2a437e0-aeea-5e14-ae20-8a53cb85c225', 'وضعيّة (كيمياء): سُخّن 8 g من النحاس في الهواء فاتّحد بالأكسجين وأعطى 10 g من أكسيد النحاس. ما كتلة الأكسجين التي اتّحدت مع النحاس؟', '[{"id":"a","text":"18 g"},{"id":"b","text":"2 g"},{"id":"c","text":"8 g"},{"id":"d","text":"10 g"}]'::jsonb, 'b', 'بمبدأ انحفاظ الكتلة: كتلة المتفاعلات = كتلة النواتج، أي m(نحاس) + m(أكسجين) = m(أكسيد النحاس). إذن m(أكسجين) = 10 − 8 = 2 g. الخيار 18 g خطأ ناتج عن جمع الكتل بدل طرحها.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('230f10ac-5918-548b-8e11-39060aaed475', 'e2a437e0-aeea-5e14-ae20-8a53cb85c225', 'وضعيّة (ضوء): وُضع جسم أمام عدسة مجمّعة على بُعد يساوي تمامًا ضعف البُعد البؤري (d = 2f). ما طبيعة الصورة وحجمها؟', '[{"id":"a","text":"حقيقية مقلوبة مصغّرة"},{"id":"b","text":"حقيقية مقلوبة مساوية للجسم في الحجم"},{"id":"c","text":"تخيّليّة معتدلة مكبّرة"},{"id":"d","text":"حقيقية معتدلة مكبّرة"}]'::jsonb, 'b', 'عند d = 2f تتكوّن صورة حقيقية (الأشعّة تتقاطع فعليًّا)، مقلوبة (لتقاطع الأشعّة)، ومساوية للجسم في الحجم (التكبير |γ| = 1). وهذه الحالة هي الحدّ الفاصل بين الصورة المصغّرة (d > 2f) والمكبّرة (f < d < 2f).', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('4206e6fd-2b14-5b27-91eb-8c40852de0c6', 'e2a437e0-aeea-5e14-ae20-8a53cb85c225', 'وضعيّة (كهرباء) — تتمّة السؤال السابق (I = 0,4 A ; R₁ = 10 Ω): ما التوتر U₁ على طرفَي المقاومة R₁؟', '[{"id":"a","text":"6 V"},{"id":"b","text":"4 V"},{"id":"c","text":"2 V"},{"id":"d","text":"25 V"}]'::jsonb, 'b', 'التيار نفسه يمرّ في كلّ عناصر التسلسل (I = 0,4 A). نطبّق قانون أوم على R₁: U₁ = R₁ × I = 10 × 0,4 = 4 V. وللتحقّق: U₂ = R₂ × I = 5 × 0,4 = 2 V، ومجموعهما U₁ + U₂ = 4 + 2 = 6 V = توتر المصدر ✓.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('baf3dea8-a92c-5685-a52a-02d988942e1d', 'e2a437e0-aeea-5e14-ae20-8a53cb85c225', 'وضعيّة (كيمياء): يُمثَّل احتراق الكربون في وفرة من الأكسجين بالمعادلة غير الموزونة C + O₂ → CO. ما الموازنة الصحيحة لتكوين أحادي أكسيد الكربون CO؟', '[{"id":"a","text":"C + O₂ → CO"},{"id":"b","text":"2C + O₂ → 2CO"},{"id":"c","text":"C + 2O₂ → 2CO"},{"id":"d","text":"2C + 2O₂ → 2CO"}]'::jsonb, 'b', 'في الصيغة الأصلية الأكسجين 2 يسارًا (O₂) و1 يمينًا (CO) فهي غير موزونة. بوضع 2C + O₂ → 2CO: الكربون يسارًا 2 ويمينًا 2×1=2 ✓؛ الأكسجين يسارًا 2 ويمينًا 2×1=2 ✓. إذن المعادلة موزونة. نوازن بتغيير المعاملات فقط لا الأرقام السفلية.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('8c02a838-5105-5c40-9106-8b252a765096', 'e2a437e0-aeea-5e14-ae20-8a53cb85c225', 'وضعيّة (ضوء): عدسة مجمّعة قدرتها C = 4 δ. ما بُعدها البؤري f بالسنتيمتر؟', '[{"id":"a","text":"f = 4 cm"},{"id":"b","text":"f = 0,25 cm"},{"id":"c","text":"f = 25 cm"},{"id":"d","text":"f = 40 cm"}]'::jsonb, 'c', 'من العلاقة C = 1/f نستخرج f = 1/C = 1/4 = 0,25 m. والمطلوب بالسنتيمتر: 0,25 m = 25 cm. الخيار 4 cm خطأ ناتج عن الخلط بين القدرة والبُعد البؤري، والخيار 0,25 cm خطأ في عدم تحويل المتر إلى سنتيمتر.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.exercises (id, chapter_id, subject_id, title, difficulty, xp_reward, reward_coins, mode, source, display_order) VALUES
  ('cfb1570d-afbc-532a-84f8-7a206484383c', 'b2e35220-fa37-5041-9ccc-4f6185e73e37', 'svt', '👑 تحدّي النخبة: سبر امتحاني شامل', 4, 300, 60, 'challenge', 'admin', 3)
ON CONFLICT (id) DO UPDATE SET
  chapter_id = EXCLUDED.chapter_id,
  subject_id = EXCLUDED.subject_id,
  title = EXCLUDED.title,
  difficulty = EXCLUDED.difficulty,
  xp_reward = EXCLUDED.xp_reward,
  reward_coins = EXCLUDED.reward_coins,
  mode = EXCLUDED.mode,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('1cd2aee2-52d5-56c4-a482-e969177b3b8d', 'cfb1570d-afbc-532a-84f8-7a206484383c', 'وضعيّة (كهرباء): مقاومتان R₁ = 6 Ω و R₂ = 3 Ω موصولتان على التوازي بمصدر U = 12 V. احسب شدّة التيار الكلّي I الذي يسحبه المصدر.', '[{"id":"a","text":"1,33 A"},{"id":"b","text":"6 A"},{"id":"c","text":"0,75 A"},{"id":"d","text":"4 A"}]'::jsonb, 'b', 'في التوازي التوتر نفسه على كلّ مقاومة (U₁ = U₂ = 12 V). نحسب تيار كلّ فرع: I₁ = U/R₁ = 12/6 = 2 A، و I₂ = U/R₂ = 12/3 = 4 A. التيار الكلّي = مجموع تيارات الفروع: I = I₁ + I₂ = 2 + 4 = 6 A. (تحقّق بالمقاومة الإجمالية: 1/R = 1/6 + 1/3 = 3/6 = 1/2 ⟹ R = 2 Ω، و I = 12/2 = 6 A ✓.)', 1)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('e45fc2a9-973d-55ef-95ef-71201603dddb', 'cfb1570d-afbc-532a-84f8-7a206484383c', 'وضعيّة (كيمياء): تحترق صفيحة من المغنيزيوم في الأكسجين فينتج أكسيد المغنيزيوم MgO وفق Mg + O₂ → MgO. ما الموازنة الصحيحة؟', '[{"id":"a","text":"Mg + O₂ → MgO"},{"id":"b","text":"2Mg + O₂ → 2MgO"},{"id":"c","text":"Mg + 2O₂ → 2MgO"},{"id":"d","text":"2Mg + 2O₂ → 2MgO"}]'::jsonb, 'b', 'في الصيغة الأصلية الأكسجين 2 يسارًا (O₂) و1 يمينًا (MgO) فهي غير موزونة. بوضع 2Mg + O₂ → 2MgO: المغنيزيوم يسارًا 2 ويمينًا 2 ✓؛ الأكسجين يسارًا 2 ويمينًا 2×1=2 ✓. إذن المعادلة موزونة. تذكّر: نوازن بالمعاملات فقط.', 2)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('d63138e7-5f2f-564e-99c3-b32e3bd06537', 'cfb1570d-afbc-532a-84f8-7a206484383c', 'وضعيّة (كيمياء): في تفاعل احتراق المغنيزيوم احترق 6 g من المغنيزيوم مع 4 g من الأكسجين. ما كتلة أكسيد المغنيزيوم المتكوّن، وهل بقي متفاعل دون استهلاك إن علمنا أنّ كلّ الكتلتَين تفاعلتا؟', '[{"id":"a","text":"10 g، ولم يبقَ متفاعل"},{"id":"b","text":"2 g، وبقي أكسجين"},{"id":"c","text":"24 g، ولم يبقَ متفاعل"},{"id":"d","text":"6 g، وبقي مغنيزيوم"}]'::jsonb, 'a', 'بانحفاظ الكتلة وبما أنّ الكتلتَين تفاعلتا بالكامل: كتلة الناتج = مجموع كتل المتفاعلات = 6 + 4 = 10 g. ولأنّ المتفاعلَين استُهلكا كلّيًّا فلم يبقَ شيء. الخيار 2 g خطأ ناتج عن الطرح بدل الجمع.', 3)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('fc12a31a-4129-5b3f-8017-60fd366a6949', 'cfb1570d-afbc-532a-84f8-7a206484383c', 'وضعيّة (ضوء): جسم وُضع على بُعد OA = 30 cm أمام عدسة مجمّعة بُعدها البؤري f = 20 cm. باستعمال علاقة المقرّبات (1/OA'' − 1/OA = 1/f) مع الاتّجاه الجبري (OA = −30 cm)، ما موضع الصورة OA''؟', '[{"id":"a","text":"OA'' = +60 cm (صورة حقيقية خلف العدسة)"},{"id":"b","text":"OA'' = +12 cm (صورة حقيقية خلف العدسة)"},{"id":"c","text":"OA'' = −60 cm (صورة تخيّليّة أمام العدسة)"},{"id":"d","text":"OA'' = +50 cm (صورة حقيقية خلف العدسة)"}]'::jsonb, 'a', 'نطبّق العلاقة: 1/OA'' = 1/f + 1/OA = 1/20 + 1/(−30). بتوحيد المقام (60): = 3/60 − 2/60 = 1/60 ⟹ OA'' = +60 cm. الإشارة الموجبة تدلّ على أنّ الصورة خلف العدسة (في الجهة المقابلة للجسم)، فهي صورة حقيقية. ولأنّ f < OA < 2f (20 < 30 < 40) فالصورة مكبّرة.', 4)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('f469f129-db29-5c93-8857-0ce1abc2b6ba', 'cfb1570d-afbc-532a-84f8-7a206484383c', 'وضعيّة (ضوء) — تتمّة: في السؤال السابق (OA = −30 cm ; OA'' = +60 cm) كان طول الجسم AB = 2 cm. ما طول الصورة |A''B''| واتّجاهها؟', '[{"id":"a","text":"|A''B''| = 4 cm، مقلوبة"},{"id":"b","text":"|A''B''| = 4 cm، معتدلة"},{"id":"c","text":"|A''B''| = 1 cm، مقلوبة"},{"id":"d","text":"|A''B''| = 2 cm، مقلوبة"}]'::jsonb, 'a', 'نحسب التكبير الخطّي: γ = OA''/OA = (+60)/(−30) = −2. الإشارة السالبة تعني الصورة مقلوبة، و|γ| = 2 يعني مكبّرة مرّتين. طول الصورة: |A''B''| = |γ| × AB = 2 × 2 = 4 cm. إذن صورة مقلوبة طولها 4 cm، وهو ما يوافق الصورة الحقيقية المكبّرة عندما يكون الجسم بين f و 2f.', 5)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('de42712b-4607-538b-989e-490da770e0fc', 'cfb1570d-afbc-532a-84f8-7a206484383c', 'وضعيّة (كهرباء/تركيب): دارة فيها مصدر U = 12 V يغذّي مقاومتَين على التسلسل R₁ = 4 Ω و R₂ = 8 Ω. ما القدرة الكهربائية المستهلكة في R₂ (تُحسب بـ P = U₂ × I)؟', '[{"id":"a","text":"8 W"},{"id":"b","text":"1 A فقط"},{"id":"c","text":"16 W"},{"id":"d","text":"96 W"}]'::jsonb, 'a', 'الخطوة 1 — التيار: R_total = R₁ + R₂ = 4 + 8 = 12 Ω، و I = U/R_total = 12/12 = 1 A (نفسه في كلّ التسلسل). الخطوة 2 — التوتر على R₂: U₂ = R₂ × I = 8 × 1 = 8 V. الخطوة 3 — القدرة: P₂ = U₂ × I = 8 × 1 = 8 W. الخيار 96 W خطأ ناتج عن استعمال توتر المصدر الكامل (12 V) بدل التوتر الجزئي U₂.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

